/**
 * @fileoverview Vault validation functions with action-specific error prefixes.
 *
 * Each validation function provides clear, contextual error messages that
 * identify which vault action failed validation.
 *
 * @module vault/lib/validate
 */

import * as SCHEMA      from '@/schema/index.js'
import { assert_valid } from '@/lib/validate/core.js'

import type {
  VaultBorrowRequest,
  VaultDepositRequest,
  VaultCloseRequest,
  VaultRepayRequest,
  VaultRepoRequest,
  VaultTrimRequest,
  VaultOpenRequest,
  VaultWithdrawRequest
} from '@ducat-unit/core'
import type {
  VaultOpenRequestConfig,
  VaultBorrowRequestConfig,
  VaultRepayRequestConfig,
  VaultDepositRequestConfig,
  VaultCloseRequestConfig,
  VaultWithdrawRequestConfig,
  VaultRepoRequestConfig,
  VaultTrimRequestConfig
} from '@/types/index.js'

/** Validate typed config payload for `open` action. */
export function validate_vault_open_config (
  req_config : unknown
) : asserts req_config is VaultOpenRequestConfig {
  assert_valid(SCHEMA.module.vault.config.open_config, req_config, 'vault open config')
}

