/**
 * @fileoverview Validator API fetch helper for looking up coin data by coin ID.
 */

import { Fetch, Resolve }          from '@vbyte/util'
import { validate_fetch_response, safe_path_segment } from './util.js'
import * as SCHEMA                 from '@/schema/index.js'

import type { CoinData } from '@/types/index.js'

/**
 * Fetches data for a single coin by ID from the validator API
 * @param host_url - Base URL of the validator API server
 * @param coin_id  - The coin ID to lookup data for
 * @returns Coin data with assets, commits, and optional vault or error response
 */
export async function fetch_coin_data (
  host_url : string,
  coin_id  : string
) : Promise<Resolve.Type<CoinData>> {
  const seg = safe_path_segment(coin_id, 'coin_id')
  const url = `${host_url}/api/coin/${seg}`
  const res = await Fetch.json(url)
  if (!res.ok) return res
  return validate_fetch_response(
    SCHEMA.fetch.coin_data,
    res.data,
    'coin data validation failed'
  )
}
