/**
 * @fileoverview Vault Open API - Create new DUCAT vaults with initial deposits.
 *
 * The vault open action creates a new vault with an initial BTC deposit and
 * optional UNIT borrowing. This is the entry point for users to begin using
 * the DUCAT protocol.
 *
 * ## Two-Transaction Pattern
 *
 * The open action uses a two-PSBT pattern:
 * 1. **Issue TX (PSBT 1)**: Creates the UNIT issuance via Runestone protocol
 * 2. **Vault TX (PSBT 2)**: Creates the vault UTXO with guardian co-signature
 *
 * ## Usage
 *
 * ```typescript
 * import { VaultOpenAPI } from '@ducat-unit/client-sdk/vault'
 *
 * // 1. Create context from configuration
 * const ctx = VaultOpenAPI.create_ctx(config)
 *
 * // 2. Create unsigned PSBTs
 * const psbts = VaultOpenAPI.create_psbts(ctx)
 *
 * // 3. Sign and create request
 * const signed = await wallet.sign.batch(psbts)
 * const request = VaultOpenAPI.create_request(ctx, signed)
 * ```
 *
 * @module vault/api/open
 */

import { Assert }               from '@vbyte/util'
import { PSBT }                 from '@ducat-unit/core'
import { get_coin_total_value } from '@ducat-unit/core/lib'
import { get_txid }             from '@vbyte/btc-dev/tx'
import { PSBT_CONFIG, TXMAP }   from '@/const.js'
import {
  emit_debug,
  emit_info,
  with_observe_span
} from '@/lib/observe/index.js'

import {
  finalize_cosign_inputs,
  finalize_spending_inputs,
  create_unit_issue_runestone,
  create_issue_account_output,
  create_unit_change_output,
  create_unit_spend_input,
  create_sats_change_output,
  create_vault_commit_input,
  create_vault_return_output,
  create_vault_output,
  verify_vault_request_psbt,
  verify_vault_action_rules,
  validate_vault_open_config,
  create_vault_ctx,
  create_vault_request,
  create_unit_account_input,
  create_issue_change_output,
  create_vault_commit_vout,
  validate_vault_open_request
} from '../lib/index.js'

import type {
  VaultOpenRequest
} from '@ducat-unit/core'
import type {
  VaultOpenRequestCtx,
  VaultOpenRequestConfig
} from '@/types/index.js'

/**
 * Define the indexes for our transaction input/output types.
 */
const UNIT_XFER_VOUT = TXMAP.UNIT_ISSUE.VOUT.UNIT
const UNIT_CONN_VOUT = TXMAP.UNIT_ISSUE.VOUT.CONN

/**
 * Create a context object for a Vault Open action.
 *
 * @param vault_config - User-provided vault-open configuration.
 * @returns Validated vault-open request context.
 */
export function create_vault_open_ctx (
  vault_config : VaultOpenRequestConfig
) : VaultOpenRequestCtx {
  // Validate the configuration for a vault open action.
  validate_vault_open_config(vault_config)
  // Return the vault context object.
  return create_vault_ctx(vault_config)
}

/**
 * Create the UNIT issue/funding PSBT for vault-open.
 *
 * @param vault_ctx - Vault-open request context.
 * @returns Encoded issue PSBT.
 */
export function create_vault_open_psbt_1 (vault_ctx : VaultOpenRequestCtx) {
  return with_observe_span(
    vault_ctx.observe,
    'vault.open.create_issue_psbt',
    { fund_input_count : vault_ctx.fund_inputs.length },
    scope => {
      const { fund_inputs, issue_account, unit_postage } = vault_ctx
      const fund_value = get_coin_total_value(fund_inputs)
      const conn_value = fund_value - unit_postage
      const pdata = PSBT.create_psbt(PSBT_CONFIG)
      // issue output
      pdata.addOutput(create_issue_account_output(vault_ctx))
      // issue change
      pdata.addOutput(create_issue_change_output(vault_ctx))
      // vault commit
      pdata.addOutput(create_vault_commit_vout(vault_ctx, conn_value))
      // OP_RETURN data
      pdata.addOutput(create_unit_issue_runestone(vault_ctx))
      // issue input
      pdata.addInput(create_unit_account_input(issue_account))
      // fund inputs
      for (const utxo of fund_inputs) {
        pdata.addInput(PSBT.create_psbt_input(utxo))
      }
      PSBT.assert_is_funded(pdata)
      const psbt = PSBT.encode_psbt(pdata)
      emit_info(scope, 'vault.open.psbt.issue.created', 'created vault open issue PSBT', {
        psbt_length : psbt.length
      })
      return psbt
    }
  )
}

/**
 * Create the vault-state update PSBT for vault-open.
 *
 * @param vault_ctx - Vault-open request context.
 * @param issue_psbt - Encoded issue PSBT from phase 1.
 * @returns Encoded vault PSBT.
 */
export function create_vault_open_psbt_2 (
  vault_ctx  : VaultOpenRequestCtx,
  issue_psbt : string | Uint8Array
) {
  return with_observe_span(
    vault_ctx.observe,
    'vault.open.create_vault_psbt',
    { issue_psbt_length : typeof issue_psbt === 'string' ? issue_psbt.length : issue_psbt.length },
    scope => {
      const { change_value, unit_balance, vault_balance } = vault_ctx
      const issue_pdata = PSBT.parse_psbt(issue_psbt)
      const unit_utxo   = PSBT.extract_utxo(issue_pdata, UNIT_XFER_VOUT)
      const conn_utxo   = PSBT.extract_utxo(issue_pdata, UNIT_CONN_VOUT)
      const pdata = PSBT.create_psbt(PSBT_CONFIG)
      // unit change
      pdata.addOutput(create_unit_change_output(vault_ctx))
      // vault output
      pdata.addOutput(create_vault_output(vault_ctx, unit_balance, vault_balance))
      // sats change
      pdata.addOutput(create_sats_change_output(vault_ctx, change_value))
      // OP_RETURN data
      pdata.addOutput(create_vault_return_output(vault_ctx))
      // unit input
      pdata.addInput(create_unit_spend_input(unit_utxo))
      // commit input
      pdata.addInput(create_vault_commit_input(vault_ctx, conn_utxo))
      PSBT.assert_is_funded(pdata)
      const psbt = PSBT.encode_psbt(pdata)
      emit_info(scope, 'vault.open.psbt.vault.created', 'created vault open vault PSBT', {
        psbt_length : psbt.length
      })
      return psbt
    }
  )
}

/**
 * Create both PSBTs required for vault-open.
 *
 * @param vault_ctx - Vault-open request context.
 * @returns Tuple-like array `[issuePsbt, vaultPsbt]`.
 */
export function create_vault_open_psbt_pkg (
  vault_ctx : VaultOpenRequestCtx
) : string[] {
  return with_observe_span(
    vault_ctx.observe,
    'vault.open.create_psbts',
    {},
    scope => {
      const issue_psbt = create_vault_open_psbt_1(vault_ctx)
      const vault_psbt = create_vault_open_psbt_2(vault_ctx, issue_psbt)
      emit_debug(scope, 'vault.open.create_psbts.complete', {
        issue_psbt_length : issue_psbt.length,
        vault_psbt_length : vault_psbt.length
      })
      return [ issue_psbt, vault_psbt ]
    }
  )
}

/**
 * Create a signed guardian request payload for vault-open.
 *
 * @param vault_ctx - Vault-open request context.
 * @param signed_psbts - Signed PSBT package `[issue, vault]`.
 * @returns Validated vault-open request payload.
 */
export function create_vault_open_request (
  vault_ctx    : VaultOpenRequestCtx,
  signed_psbts : string[]
) : VaultOpenRequest {
  return with_observe_span(
    vault_ctx.observe,
    'vault.open.create_request',
    { signed_psbt_count : signed_psbts.length },
    scope => {
      const [ signed_issue_psbt, signed_vault_psbt ] = signed_psbts
      Assert.exists(signed_issue_psbt, 'issue PSBT is undefined')
      Assert.exists(signed_vault_psbt, 'vault PSBT is undefined')
      const context = create_vault_request(vault_ctx)
      const issue_pdata = PSBT.parse_psbt(signed_issue_psbt)
      const vault_pdata = PSBT.parse_psbt(signed_vault_psbt)
      finalize_spending_inputs(issue_pdata)
      finalize_cosign_inputs(vault_pdata)
      verify_vault_request_psbt(issue_pdata, 0)
      verify_vault_request_psbt(vault_pdata, vault_ctx.txfee_rate, {
        ...vault_ctx.validation_options,
        asset_pdata: issue_pdata,
        observe: vault_ctx.observe
      })
      const issue_txid = get_txid(issue_pdata.hex)
      const vault_txid = get_txid(vault_pdata.hex)
      verify_vault_action_rules(vault_ctx, vault_txid)
      const issue_psbt = PSBT.encode_psbt(issue_pdata)
      const vault_psbt = PSBT.encode_psbt(vault_pdata)
      const request = { ...context, issue_psbt, issue_txid, vault_psbt, vault_txid }
      validate_vault_open_request(request)
      emit_info(scope, 'vault.open.request.created', 'created vault open guardian request', {
        issue_txid,
        vault_txid
      })
      return request
    }
  )
}

/**
 * Export the API for the vault open action.
 */
export namespace VaultOpenAPI {
  export const create_ctx     = create_vault_open_ctx
  export const create_psbts   = create_vault_open_psbt_pkg
  export const create_request = create_vault_open_request
}
