/**
 * @fileoverview Builds the taproot commit script tree for a vault.
 */

import { Buff }                from '@vbyte/buff'
import { Assert }              from '@vbyte/util'
import { encode_script }       from '@vbyte/btc-dev/script'
import { create_vault_commit } from '@/lib/index.js'

import type { PriceCommitData } from '@ducat-unit/core'
import type { VaultRequestCtx } from '@/module/vault/types/context.js'

/**
 * Create the script tree for a vault commit.
 */
export function create_commit_script (
  vault_ctx : VaultRequestCtx
) : Uint8Array {
  // Unpack the vault context.
  const { client_pubkey, guard_pubkey, proto_profile, vault_config } = vault_ctx
  // Assert that the vault config is defined.
  Assert.exists(vault_config, 'vault config is missing from vault context')
  // Create the commit payload.
  const payload = create_vault_commit(proto_profile, vault_config)
  // Create the locking script.
  const lock_script = encode_script([ client_pubkey, 'OP_CHECKSIGVERIFY', guard_pubkey, 'OP_CHECKSIG' ])
  // Join the scripts together to create the full open script.
  return Buff.join([ lock_script, payload ])
}

/**
 * Create the script tree for a vault connector utxo.
 */
export function create_connector_script (
  client_pubkey : string,
  guard_pubkey  : string
) : Uint8Array {
  return encode_script([ client_pubkey, 'OP_CHECKSIGVERIFY', guard_pubkey, 'OP_CHECKSIG' ])
}

/**
 * Create the script tree for a vault output utxo.
 */
export function create_cleared_vault_script_tree (
  client_pubkey : string,
  guard_pubkeys : string[]
) : Uint8Array[] {
  const scripts = []
  for (const guard_pubkey of guard_pubkeys) {
    scripts.push(encode_script([ client_pubkey, 'OP_CHECKSIGVERIFY', guard_pubkey, 'OP_CHECKSIG' ]))
  }
  // Return the encoded script within a tree.
  return scripts
}

/**
 * Create the script tree for a locked vault output utxo.
 */
export function create_pledged_vault_script_tree (
  client_pubkey : string,
  guard_pubkeys : string[],
  price_commits : PriceCommitData[]
) : Uint8Array[] {
  const scripts = []
  for (const guard_pubkey of guard_pubkeys) {
    scripts.push(create_connector_script(client_pubkey, guard_pubkey))
    for (const commit of price_commits) {
      scripts.push(encode_script([ 'OP_HASH160', commit.thold_hash, 'OP_EQUALVERIFY', guard_pubkey, 'OP_CHECKSIG' ]))
    }
  }
  return scripts
}
