/**
 * @fileoverview Witness size calculations for vault transactions.
 *
 * This module provides functions for calculating the dynamic witness sizes
 * based on the actual taproot script tree structure. The key insight is that
 * control block size varies with tree depth, which depends on the number of
 * guardian scripts and price commit scripts.
 *
 * Key formulas:
 * - script_count = guard_count × (1 + price_commit_count) for pledged vaults
 * - tree_depth = ceil(log2(script_count)) for script_count > 1
 * - control_block_size = 33 + (32 × tree_depth) bytes
 * - sigops_vsize = ceil((65 × sigops_count) / 4) vbytes
 */

import { TXSIZE }              from '@/const.js'
import { PRICE_COMMIT_SIZE }   from '@ducat-unit/core/const'
import { create_vault_commit } from '@/lib/index.js'

import type { ProtoProfile, VaultConfigData } from '@ducat-unit/core/types'

/** Convert sigops count to virtual size using witness discount rules. */
export function get_sigops_vsize (sigops_count : number) : number {
  return Math.ceil((65 * sigops_count) / 4)
}

/**
 * Calculate the witness vsize for a vault input (connect).
 *
 * @param commit_size - Size of the commit script
 * @returns Witness vsize in virtual bytes
 */
export function get_vault_connect_witness_vsize (commit_size : number = 0) : number {
  const { P2TR_SIG_SIZE, COSIGN_SPEND_SCRIPT_SIZE, STACK_COUNT } = TXSIZE
  const cblock_size   = get_control_block_size(1)
  const sig_size      = P2TR_SIG_SIZE * 2
  const script_size   = COSIGN_SPEND_SCRIPT_SIZE + commit_size
  const witness_bytes = STACK_COUNT + sig_size + script_size + cblock_size
  return Math.ceil(witness_bytes / 4)
}

/**
 * Calculate the witness vsize for a vault input (spend).
 *
 * @param guard_count  - Number of guardians
 * @param oracle_count - Number of price commits
 * @returns Witness vsize in virtual bytes
 */
export function get_vault_spend_witness_vsize (
  guard_count  : number,
  oracle_count : number
): number {
  const { P2TR_SIG_SIZE, COSIGN_SPEND_SCRIPT_SIZE, STACK_COUNT } = TXSIZE
  // Get the taproot script tree count.
  const script_count  = get_vault_script_tree_count(guard_count, oracle_count)
  // Get the control block size.
  const cblock_size   = get_control_block_size(script_count)
  // Get the signature size.
  const sig_size      = P2TR_SIG_SIZE * 2
  // Get the script size.
  const script_size   = COSIGN_SPEND_SCRIPT_SIZE
  // Get the total witness size.
  const witness_bytes = STACK_COUNT + sig_size + script_size + cblock_size 
  // Return the total size with witness discount.
  return Math.ceil(witness_bytes / 4)
}

/**
 * Calculate the total input size for a liquidation transaction.
 *
 * @param guard_count  - Number of guardians
 * @param oracle_count - Number of price commits
 * @param liquid_count - Number of liquid vaults
 * @returns Input size in bytes
 */
export function get_vault_liquidation_total_size (
  guard_count  : number,
  oracle_count : number,
  liquid_count : number
): number {
  // Unpack the transaction sizes.
  const { 
    VIN_BASE_SIZE, VOUT_P2TR_SIZE, P2TR_SIG_SIZE,
    HASH_PREIMG_SIZE, LIQUID_SPEND_SCRIPT_SIZE, STACK_COUNT
  } = TXSIZE
  // Get the taproot script tree count.
  const script_count  = get_vault_script_tree_count(guard_count, oracle_count)
  // Get the control block size.
  const cblock_size   = get_control_block_size(script_count)
  // Get the signature size.
  const sig_size      = P2TR_SIG_SIZE + HASH_PREIMG_SIZE
  // Get the script size.
  const script_size   = LIQUID_SPEND_SCRIPT_SIZE
  // Get the total witness size.
  const witness_bytes = STACK_COUNT + sig_size + script_size + cblock_size
  // Return the total input/output size with witness discount.
  const liquid_pair_size = VIN_BASE_SIZE + VOUT_P2TR_SIZE + Math.ceil(witness_bytes / 4)
  // Return the total input/output size multiplied by the liquid count.
  return liquid_pair_size * liquid_count
}

/**
 * Calculate the control block size in bytes for a Taproot script spend.
 *
 * The control block contains:
 * - 1 byte: leaf version and parity
 * - 32 bytes: internal public key
 * - 32 bytes × tree_depth: merkle path hashes
 *
 * Total: 33 + (32 × tree_depth) bytes
 *
 * @param script_count - Number of scripts in the Taproot tree
 * @returns Control block size in bytes
 */
export function get_control_block_size (script_count: number): number {
  // Get the control block sizes.
  const { CBLOCK_KEY_SIZE, CBLOCK_HASH_SIZE } = TXSIZE
  // If there one or less scripts, return the cblock size.
  if (script_count <= 1) return CBLOCK_KEY_SIZE
  // Otherwise, add the tree depth times the hash size.
  const tree_depth = Math.ceil(Math.log2(script_count))
  // Return the total cblock size.
  return CBLOCK_KEY_SIZE + (CBLOCK_HASH_SIZE * tree_depth)
}

/**
 * Calculate the number of scripts in a vault's Taproot tree.
 *
 * For encumbered vaults (with oracles):
 * - Each guardian has (1 + price_commit_count) scripts:
 *   - 1 co-sign script for normal operations
 *   - N liquidation scripts for each price commit threshold
 *
 * For cleared vaults (no price commits):
 * - Each guardian has 1 co-sign script
 *
 * @param guard_count - Number of guardians
 * @param oracle_count - Number of price oracles
 * @returns Total script count in the Taproot tree
 */
export function get_vault_script_tree_count (
  guard_count  : number,
  oracle_count : number
): number {
  // If there are no oracles, the script tree count is just the guardian count.
  if (oracle_count === 0) return guard_count
  // Otherwise, the script tree count is the guardian count times the oracle count plus the guardian count.
  return guard_count * (oracle_count + 1)
}

/**
 * Calculate the size of the vault commit script.
 *
 * @param proto_profile - The protocol profile
 * @param vault_config  - The vault commit data
 * @returns Vault commit script size in bytes
 */
export function get_vault_commit_script_size (
  proto_profile : ProtoProfile,
  vault_config  : VaultConfigData
): number {
  // Create the vault commit payload.
  const vault_commit = create_vault_commit(proto_profile, vault_config)
  // Return the vault commit script size in bytes.
  return vault_commit.length / 2
}

/**
 * Calculate the size of the liquid reserve output.
 *
 * @param reserve_balance - The reserve balance in sats
 * @returns Liquid reserve output size in bytes
 */
export function get_liquid_reserve_output_size (
  reserve_balance : number
) : number {
  // Return the liquid reserve output size in bytes.
  return (reserve_balance > 0) ? TXSIZE.VOUT_P2TR_SIZE : 0
}

/**
 * Calculate the size of the vault return data.
 *
 * @param guard_count  - Number of guardians
 * @param oracle_count - Number of price oracles
 * @returns Vault return data size in bytes
 */
export function get_vault_return_size (
  guard_count  : number,
  oracle_count : number,
  unit_balance : number
): number {
  const { VAULT_RETURN_BASE_SIZE, VAULT_RETURN_GUARD_DATA, VAULT_RETURN_PRICE_DATA } = TXSIZE
  // Get the base size.
  const base_data_size  = VAULT_RETURN_BASE_SIZE 
  // Get the guard size.
  const guard_data_size = VAULT_RETURN_GUARD_DATA + guard_count
  // If there are no oracles, the return size is the base size.
  if (unit_balance === 0) return base_data_size + guard_data_size
  // Get the price size.
  const price_data_size = VAULT_RETURN_PRICE_DATA + (oracle_count * PRICE_COMMIT_SIZE)
  // Otherwise, the return size is the base size plus the unit balance size.
  return base_data_size + guard_data_size + price_data_size
}
