/**
 * @fileoverview Vault Withdraw API - Remove BTC collateral from vaults.
 *
 * The withdraw action allows vault owners to remove BTC collateral from their
 * vault. This decreases the collateral ratio, so withdrawals are constrained
 * by the minimum collateral ratio requirement.
 *
 * ## Single-Transaction Pattern
 *
 * Like deposit, withdraw uses a single PSBT since no UNIT tokens are involved.
 * The vault UTXO is updated with the new (lower) balance.
 *
 * ## Collateral Requirements
 *
 * Withdrawals must leave sufficient collateral to maintain the minimum ratio
 * (typically 150%). Attempting to withdraw too much will fail validation.
 *
 * ## Usage
 *
 * ```typescript
 * import { VaultWithdrawAPI } from '@ducat-unit/client-sdk/vault'
 *
 * const ctx = VaultWithdrawAPI.create_ctx(config)
 * const psbt = VaultWithdrawAPI.create_psbt(ctx)
 * const signed = await wallet.sign.psbt(psbt)
 * const request = VaultWithdrawAPI.create_request(ctx, signed)
 * ```
 *
 * @module vault/api/withdraw
 */

import { get_txid }    from '@vbyte/btc-dev/tx'
import { PSBT }        from '@ducat-unit/core'
import { PSBT_CONFIG } from '@/const.js'
import {
  emit_info,
  with_observe_span
} from '@/lib/observe/index.js'

import {
  create_sats_change_output,
  create_vault_return_output,
  create_vault_spend_input,
  create_vault_output,
  finalize_cosign_inputs,
  finalize_spending_inputs,
  verify_vault_request_psbt,
  verify_vault_action_rules,
  create_vault_ctx,
  validate_vault_withdraw_config,
  create_vault_request,
  validate_vault_withdraw_request
} from '../lib/index.js'

import type {
  VaultWithdrawRequest
} from '@ducat-unit/core'
import type {
  VaultWithdrawRequestCtx,
  VaultWithdrawRequestConfig
} from '@/types/index.js'

/**
 * Create a context object for a Vault Withdraw action.
 *
 * @param vault_config - User-provided vault-withdraw configuration.
 * @returns Validated vault-withdraw request context.
 */
export function create_vault_withdraw_ctx (
  vault_config : VaultWithdrawRequestConfig
) : VaultWithdrawRequestCtx {
  // Validate the configuration for a vault withdraw action.
  validate_vault_withdraw_config(vault_config)
  // Return the vault context object.
  return create_vault_ctx(vault_config)
}

/**
 * Create the vault-state update PSBT for vault-withdraw.
 *
 * @param vault_ctx - Vault-withdraw request context.
 * @returns Encoded vault PSBT.
 */
export function create_vault_withdraw_psbt (
  vault_ctx : VaultWithdrawRequestCtx
) {
  return with_observe_span(
    vault_ctx.observe,
    'vault.withdraw.create_psbt',
    {},
    scope => {
      const { unit_balance, vault_balance, withdraw_amount } = vault_ctx
      const pdata = PSBT.create_psbt(PSBT_CONFIG)
      pdata.addOutput(create_vault_output(vault_ctx, unit_balance, vault_balance))
      pdata.addOutput(create_sats_change_output(vault_ctx, withdraw_amount))
      pdata.addOutput(create_vault_return_output(vault_ctx))
      pdata.addInput(create_vault_spend_input(vault_ctx))
      PSBT.assert_is_funded(pdata)
      const psbt = PSBT.encode_psbt(pdata)
      emit_info(scope, 'vault.withdraw.psbt.created', 'created vault withdraw PSBT', {
        psbt_length : psbt.length
      })
      return psbt
    }
  )
}

/**
 * Create a signed guardian request payload for vault-withdraw.
 *
 * @param vault_ctx - Vault-withdraw request context.
 * @param vault_psbt - Signed vault PSBT.
 * @returns Validated vault-withdraw request payload.
 */
export function create_vault_withdraw_request (
  vault_ctx  : VaultWithdrawRequestCtx,
  vault_psbt : string
) : VaultWithdrawRequest {
  return with_observe_span(
    vault_ctx.observe,
    'vault.withdraw.create_request',
    { signed_psbt_length : vault_psbt.length },
    scope => {
      const context = create_vault_request(vault_ctx)
      const vault_pdata = PSBT.parse_psbt(vault_psbt)
      finalize_spending_inputs(vault_pdata)
      finalize_cosign_inputs(vault_pdata)
      verify_vault_request_psbt(vault_pdata, vault_ctx.txfee_rate, { ...vault_ctx.validation_options, observe: vault_ctx.observe })
      const vault_txid = get_txid(vault_pdata.hex)
      verify_vault_action_rules(vault_ctx, vault_txid)
      vault_psbt = PSBT.encode_psbt(vault_pdata)
      const request = { ...context, vault_psbt, vault_txid }
      validate_vault_withdraw_request(request)
      emit_info(scope, 'vault.withdraw.request.created', 'created vault withdraw guardian request', {
        vault_txid
      })
      return request
    }
  )
}

/**
 * Export the API for the vault withdraw action.
 */
export namespace VaultWithdrawAPI {
  export const create_ctx     = create_vault_withdraw_ctx
  export const create_psbt    = create_vault_withdraw_psbt
  export const create_request = create_vault_withdraw_request
}
