/**
 * @fileoverview Validator API fetch helpers for asset accounts, history, and stats.
 */

import { Fetch, Resolve }          from '@vbyte/util'
import {
  validate_fetch_list_response,
  validate_fetch_response,
  safe_path_segment
} from './util.js'
import * as SHARED                 from '@ducat-unit/core/schema'
import * as SCHEMA                 from '@/schema/index.js'

import type { AssetAccount }  from '@ducat-unit/core'
import type { AssetStats }    from '@/types/index.js'

/**
 * Fetches asset accounts for a given Bitcoin address from the validator API
 * @param host_url - Base URL of the validator API server
 * @param address  - Bitcoin address to lookup asset accounts for
 * @returns Array of asset account data or error response
 */
export async function fetch_asset_data (
  host_url : string,
  address  : string
) : Promise<Resolve.Type<AssetAccount[]>> {
  const seg = safe_path_segment(address, 'address')
  const url = `${host_url}/api/address/${seg}`
  const res = await Fetch.json(url)
  if (!res.ok) return res
  return validate_fetch_list_response(
    SHARED.asset.account.array(),
    res.data,
    'asset data validation failed'
  )
}

/**
 * Fetches asset account history for a given asset ID
 * @param host_url - Base URL of the validator API server
 * @param asset_id - The asset ID to lookup history for
 * @param page_size - Maximum number of records to return
 * @param cursor   - Opaque cursor for the next page
 * @returns Array of asset account data or error response
 */
export async function fetch_asset_history (
  host_url : string,
  asset_id : string,
  page_size? : number,
  cursor?  : string
) : Promise<Resolve.Type<AssetAccount[]>> {
  const seg = safe_path_segment(asset_id, 'asset_id')
  const url = new URL(`${host_url}/api/asset/${seg}/history`)
  if (page_size !== undefined) url.searchParams.set('page_size', String(page_size))
  if (cursor !== undefined) url.searchParams.set('cursor', cursor)
  const res = await Fetch.json(url.toString())
  if (!res.ok) return res
  return validate_fetch_list_response(
    SHARED.asset.account.array(),
    res.data,
    'asset history validation failed'
  )
}

/**
 * Fetches aggregate stats for a given asset ID
 * @param host_url - Base URL of the validator API server
 * @param asset_id - The asset ID to lookup stats for
 * @returns Asset stats data or error response
 */
export async function fetch_asset_stats (
  host_url : string,
  asset_id : string
) : Promise<Resolve.Type<AssetStats>> {
  const seg = safe_path_segment(asset_id, 'asset_id')
  const url = `${host_url}/api/asset/${seg}/stats`
  const res = await Fetch.json(url)
  if (!res.ok) return res
  return validate_fetch_response(
    SCHEMA.fetch.asset_stats,
    res.data,
    'asset stats validation failed'
  )
}
