/**
 * @fileoverview Vault action quote generation.
 *
 * This module creates comprehensive quotes for vault actions by combining:
 * - Fee estimation (transaction sizes and fee rates)
 * - Coin context (input values and spending fees)
 * - Balance tabulation (vault and UNIT balance changes)
 *
 * A quote provides all the financial details needed to construct and fund
 * a vault action transaction.
 */

import { Assert }                      from '@vbyte/util'
import { get_asset_account_utxo }      from '@ducat-unit/core/lib'
import { get_vault_terms }             from '@ducat-unit/core/lib'
import { DEFAULT_POSTAGE, DUST_LIMIT } from '@/const.js'
import * as SCHEMA                     from '@/schema/index.js'

import {
  create_vault_action_estimate,
  emit_debug,
  get_observe_context,
  get_coin_ctx,
  get_collateral_overflow,
  tabulate_vault_balance,
  with_observe_span
} from '@/lib/index.js'

import type {
  CoinUtxo,
  VaultAction
} from '@ducat-unit/core'

import type {
  VaultActionConfig,
  VaultActionQuote,
} from '@/types/index.js'

const DEFAULT_ACTION_CONFIG = {
  asset_inputs    : [],
  borrow_amount   : 0,
  deposit_amount  : 0,
  fund_inputs     : [],
  repay_amount    : 0,
  txfee_reserve   : 0,
  unit_postage    : DEFAULT_POSTAGE,
  withdraw_amount : 0
}

/**
 * Creates a comprehensive quote for a vault action.
 *
 * @param vault_config - Configuration for the vault action.
 * @returns A VaultActionQuote containing all fee, balance, and funding details
 * @throws If coin value doesn't cover deposit and postage
 * @throws If change value is below dust limit (when non-zero)
 */
export function create_vault_action_quote (vault_config : VaultActionConfig) : VaultActionQuote {
  const observe = get_observe_context(vault_config.observability, {
    module       : 'vault.quote',
    vault_action : vault_config.vault_action
  })

  return with_observe_span(
    observe,
    `vault.${vault_config.vault_action}.quote`,
    { vault_action : vault_config.vault_action },
    scope => {
      // Unpack the vault config.
      const parsed = parse_vault_action_config(vault_config)
      // Merge the default action config with the parsed config.
      const config = { ...DEFAULT_ACTION_CONFIG, ...parsed }
      // Unpack the vault config.
      const { asset_inputs, deposit_amount, fund_inputs, price_quotes, proto_profile, txfee_rate, vault_action, vault_profile } = config
      // Validate the coin inputs.
      validate_coin_inputs(vault_action, fund_inputs)
      // Get the vault action quote.
      const estimate    = create_vault_action_estimate(config)
      // Get the action cost from the vault quote.
      const action_cost = estimate.action_fees
      // Get the asset coins.
      const asset_coins = asset_inputs.map(input => get_asset_account_utxo(input))
      // Get the coin funding context.
      const coin_ctx    = get_coin_ctx([ ...asset_coins, ...fund_inputs ], txfee_rate)
      // Unpack the coin context.
      const { coin_value, coin_fees } = coin_ctx
      // Define the rebate value.
      const fund_balance = coin_value - (deposit_amount + estimate.action_postage)
      // Assert the funds balance is greater than or equal to 0.
      Assert.ok(fund_balance >= 0, `coin value does not cover deposit and postage: ${coin_value} < ${fund_balance}`)
      // Define the total cost.
      const total_cost    = action_cost + coin_fees
      // Define the reserve balance.
      const txfee_balance = Math.max(total_cost - fund_balance, 0)
      // Collateral-adding actions (open, borrow, deposit) advertise a
      // deposit that must land in the vault output IN FULL. A positive
      // txfee_balance is the fee shortfall that tabulate_vault_balance
      // would silently subtract from that collateral, producing a vault
      // holding less than advertised (Codex F17). Require the caller to
      // fund the fee instead of shrinking the deposit. (withdraw / repay
      // / close legitimately pay fees out of collateral being removed or
      // returned, so they are exempt.)
      if (
        (vault_action === 'open' || vault_action === 'borrow' || vault_action === 'deposit') &&
        txfee_balance > 0
      ) {
        throw new Error(
          `insufficient funding for transaction fees: add ${txfee_balance} sats of input ` +
          `to cover fees rather than reducing the vault deposit`
        )
      }
      // Define the base change value (before overflow).
      let change_value  = Math.max(fund_balance - total_cost, 0)
      // Calculate the vault balance.
      let vault_balance = tabulate_vault_balance(config, txfee_balance)
      Assert.ok(
        vault_balance >= 0,
        `vault balance cannot be negative after fees: ${vault_balance}`
      )
      // Calculate overflow for repay actions that would exceed rate_max.
      let overflow_value = 0
      // Close is terminal and returns all remaining collateral to change.
      if (vault_action === 'close') {
        const prev_balance = vault_profile?.vault_balance ?? 0
        const vault_terms = get_vault_terms(proto_profile.proto_terms)
        const spendable_balance = prev_balance + vault_terms.vault_value_min
        vault_balance = 0
        change_value = Math.max(spendable_balance - txfee_balance, 0)
      }
      // If the vault action is repay and there are price quotes,
      if (vault_action === 'repay' && price_quotes && price_quotes.length > 0) {
        overflow_value = get_collateral_overflow(vault_balance, estimate.unit_balance, price_quotes, proto_profile)
        if (overflow_value > 0) {
          vault_balance -= overflow_value
          change_value  += overflow_value
        }
      }
      if (change_value > 0) {
        Assert.ok(change_value >= DUST_LIMIT, `change value is below the dust limit: ${change_value}`)
      }
      if (txfee_balance > 0) {
        const is_valid_change = (vault_action === 'close')
          ? change_value >= 0
          : (change_value === 0 || change_value === overflow_value)
        Assert.ok(is_valid_change, `cannot have a txfee balance and change value: ${txfee_balance} / ${change_value}`)
      }
      const quote = {
        ...estimate,
        ...coin_ctx,
        vault_balance,
        change_value,
        fund_balance,
        overflow_value,
        total_cost,
        txfee_balance
      }
      emit_debug(scope, `vault.${vault_action}.quote.complete`, {
        change_value,
        coin_count     : fund_inputs.length,
        overflow_value,
        total_cost,
        txfee_balance,
        vault_balance
      })
      return quote
    }
  )
}

/**
 * Parses and validates a vault action configuration using Zod schema.
 * Removes undefined values from the parsed config to allow proper merging
 * with default values.
 *
 * @param config - Raw configuration object to parse
 * @returns Validated VaultActionConfig with undefined values removed
 * @throws ZodError if the config doesn't match the expected schema
 */
function parse_vault_action_config (
  config : unknown
) : VaultActionConfig {
  // Remove `undefined` keys so explicit defaults are applied consistently
  // after schema parsing/normalization.
  const parsed = SCHEMA.vault.config.parse(config)
  for (const key of Object.keys(parsed)) {
    if ((parsed as Record<string, unknown>)[key] === undefined) {
      delete parsed[key as keyof typeof parsed]
    }
  }
  return parsed as VaultActionConfig
}

/**
 * Validates that coin inputs are appropriate for the given vault action.
 * Some actions (withdraw, trim) must not have external funding inputs
 * as they only use the vault's existing collateral.
 *
 * @param vault_action - The vault action type being performed
 * @param coin_inputs - Array of coin UTXOs provided for funding
 * @throws If coin inputs are provided for withdraw or trim actions
 */
function validate_coin_inputs (
  vault_action : VaultAction,
  coin_inputs  : CoinUtxo[]
) {
  // Withdraw/trim should be self-funded from vault state transitions and must
  // not include external funding inputs.
  if (vault_action === 'withdraw') {
    Assert.ok(coin_inputs.length === 0, 'no coin inputs allowed for vault withdraw action')
  } else if (vault_action === 'close') {
    Assert.ok(coin_inputs.length === 0, 'no coin inputs allowed for vault close action')
  } else if (vault_action === 'trim') {
    Assert.ok(coin_inputs.length === 0, 'no coin inputs allowed for vault trim action')
  }
}
