/**
 * @fileoverview UNIT-account input builders for vault flows.
 */

import { PSBT } from '@ducat-unit/core'

import {
  create_unit_asset_input,
  get_asset_account_utxo
} from '@ducat-unit/core/lib'

import type {
  AssetAccount,
  CoinUtxo,
  PSBTInput
} from '@ducat-unit/core'

/**
 * Create a PSBT input from the UNIT account's current tracked UTXO.
 * @param unit_account - UNIT asset account to spend from.
 * @returns PSBT input for the account UTXO.
 */
export function create_unit_account_input (
  unit_account : AssetAccount
) : PSBTInput {
  // Get the coin utxo for the unit account.
  const utxo  = get_asset_account_utxo(unit_account)
  // Create the tagged input.
  const input = create_unit_asset_input(utxo)
  // Create the PSBT input.
  return PSBT.create_psbt_input(input)
}

/**
 * Create a PSBT input from an explicit UNIT coin UTXO.
 * @param coin_utxo - UNIT coin UTXO to include as an input.
 * @returns PSBT input for the provided UNIT UTXO.
 */
export function create_unit_spend_input (
  coin_utxo : CoinUtxo
) : PSBTInput {
  // Create the tagged utxo.
  const utxo = create_unit_asset_input(coin_utxo)
  // Create the PSBT input.
  return PSBT.create_psbt_input(utxo)
}
