/**
 * @fileoverview Wallet signing-manifest utility helpers.
 */

import { SYMBOLS } from '@ducat-unit/core/const'

import type {
  SignPSBTManifest
} from '@/types/index.js'

const PROTO_ASSETS  = Object.values(SYMBOLS.CODE.ASSET)
const VAULT_ACTIONS = Object.values(SYMBOLS.CODE.VAULT)
const CONNECT_INPUT = SYMBOLS.CODE.INPUT.CONNECT

/**
 * Returns true when an input code maps to an asset operation.
 */
export function is_asset_input (code : number | null) : boolean {
  return code !== null && PROTO_ASSETS.includes(code)
}

/**
 * Returns true when an input code maps to a vault-related operation.
 */
export function is_vault_input (code : number | null) : boolean {
  return code !== null && (VAULT_ACTIONS.includes(code) || CONNECT_INPUT === code)
}

/**
 * Build a signing manifest from `(address, indices[])` tuples.
 * @param inputs - Address/index-group pairs to merge.
 * @returns Normalized signing manifest keyed by address.
 */
export function create_manifest (
  inputs : [ string, number[] ][]
) : SignPSBTManifest {
  // Create a manifest.
  const manifest : SignPSBTManifest = {}
  // Populate the manifest.
  for (const [ key, value ] of inputs) {
    // If the key is not in the manifest,
    if (manifest[key] === undefined) {
      // Add the key and empty array to the manifest.
      manifest[key] = []
    }
    // Add the value to the current key.
    manifest[key].push(...value)
  }
  // Return the manifest.
  return manifest
}

/**
 * Append an input index to a manifest entry for a signing address.
 * @param manifest - Existing signing manifest.
 * @param address - Signing address key.
 * @param index - Input index to append.
 */
export function update_manifest (
  manifest : SignPSBTManifest,
  address  : string,
  index    : number
) : void {
  // Initialize the entry when this address is first seen.
  if (!Array.isArray(manifest[address])) {
    manifest[address] = [ index ]
  } else {
    // Append additional input indices for the same address.
    manifest[address].push(index)
  }
}
