/**
 * @fileoverview Validator API fetch helpers for liquidation history, samples, and stats.
 */

import { Fetch, Resolve }          from '@vbyte/util'
import {
  validate_fetch_list_response,
  validate_fetch_response
} from './util.js'
import * as SHARED                 from '@ducat-unit/core/schema'
import * as SCHEMA                 from '@/schema/index.js'

import type { VaultProfile } from '@ducat-unit/core'
import type { LiquidStats, PaginatedData }  from '@/types/index.js'

/**
 * Fetch historical liquidation records.
 *
 * @param host_url - Base URL of the validator API server
 * @param page_size - Maximum number of records to return
 * @param cursor   - Opaque cursor for the next page
 * @returns Array of vault profile data or error response
 */
export async function fetch_liquid_history (
  host_url : string,
  page_size? : number,
  cursor?  : string
) : Promise<Resolve.Type<VaultProfile[]>> {
  const url = new URL(`${host_url}/api/liquid/history`)
  if (page_size !== undefined) url.searchParams.set('page_size', String(page_size))
  if (cursor !== undefined) url.searchParams.set('cursor', cursor)
  const res = await Fetch.json(url.toString())
  if (!res.ok) return res
  return validate_fetch_list_response(
    SHARED.vault.profile.array(),
    res.data,
    'liquid history validation failed'
  )
}

/**
 * Fetch a sampled set of vaults matching liquidation price criteria.
 *
 * @param host_url - Base URL of the validator API server
 * @param price    - Threshold price for liquidation
 * @param count    - Number of vaults to return
 * @param max_ratio - Optional maximum vault ratio filter
 * @returns Array of breached vault profile data or error response
 */
export async function fetch_liquid_sample (
  host_url : string,
  price    : number,
  count?   : number,
  max_ratio? : number
) : Promise<Resolve.Type<VaultProfile[]>> {
  const url = new URL(`${host_url}/api/liquid/sample`)
  url.searchParams.set('price', String(price))
  if (count !== undefined) url.searchParams.set('count', String(count))
  if (max_ratio !== undefined) url.searchParams.set('max_ratio', String(max_ratio))
  const res = await Fetch.json(url.toString())
  if (!res.ok) return res
  return validate_fetch_response(
    SHARED.vault.profile.array(),
    res.data,
    'liquid sample validation failed'
  )
}

/**
 * Fetch aggregate liquidation statistics.
 *
 * @param host_url    - Base URL of the validator API server
 * @param thold_price - Threshold price filter
 * @param page_size   - Maximum number of vaults to aggregate in this page
 * @param cursor      - Opaque cursor for the next page
 * @returns Paginated liquid stats data or error response
 */
export async function fetch_liquid_stats (
  host_url    : string,
  thold_price : number = 0,
  page_size?  : number,
  cursor?     : string
) : Promise<Resolve.Type<PaginatedData<LiquidStats>>> {
  const url = new URL(`${host_url}/api/liquid/stats`)
  url.searchParams.set('thold_price', String(thold_price))
  if (page_size !== undefined) url.searchParams.set('page_size', String(page_size))
  if (cursor !== undefined) url.searchParams.set('cursor', cursor)
  const res = await Fetch.json(url.toString())
  if (!res.ok) return res
  return validate_fetch_response(
    SCHEMA.fetch.liquid_stats_page,
    res.data,
    'liquid stats validation failed'
  )
}
