/**
 * @fileoverview Validator API fetch helper for transaction-linked index data by txid.
 */

import { Fetch, Resolve }          from '@vbyte/util'
import { validate_fetch_response, safe_path_segment } from './util.js'
import * as SCHEMA                 from '@/schema/index.js'

import type { TxData } from '@/types/index.js'

/**
 * Fetch transaction-linked index data (coins, commits, vaults) by txid.
 *
 * @param host_url - Base URL of the validator API server
 * @param txid     - The transaction ID
 * @returns Transaction data with coins, commits, and vaults or error response
 */
export async function fetch_tx_data (
  host_url : string,
  txid     : string
) : Promise<Resolve.Type<TxData>> {
  const seg = safe_path_segment(txid, 'txid')
  const url = `${host_url}/api/tx/${seg}`
  const res = await Fetch.json(url)
  if (!res.ok) return res
  return validate_fetch_response(
    SCHEMA.fetch.tx_data,
    res.data,
    'transaction data validation failed'
  )
}
