/**
 * @fileoverview Guardian API call for the vault deposit action.
 */

import { GuardianClient }     from '@/module/guard/class/client.js'
import { SocketSubscription } from '@/class/socket.js'
import { TOPICS }             from '@/const.js'
import { child_observe_context, emit_debug, emit_info, emit_warn } from '@/lib/observe/index.js'

import { validate_vault_deposit_request } from '@/module/vault/lib/validate.js'

import type {
  VaultBaseResponse,
  VaultDepositRequest
} from '@ducat-unit/core'
import type {
  MessageData
} from '@/types/index.js'

import * as SCHEMA from '@/schema/index.js'
import * as SHARED from '@ducat-unit/core/schema'

/** Build a subscription API for guardian vault-deposit signing requests. */
export function deposit_vault_api (client : GuardianClient) {

  return (
    request : VaultDepositRequest
  ) : SocketSubscription<VaultBaseResponse> => {

    validate_vault_deposit_request(request)

    const msg = { data : request, topic : TOPICS.GUARDIAN.VAULT_DEPOSIT }
    const sub = client.socket.subscribe<VaultBaseResponse>(msg)
    const observe = child_observe_context(client.observe, {
      contract_id  : request.contract_id,
      request_id   : sub.id,
      topic        : msg.topic,
      vault_action : request.vault_action
    })

    emit_info(
      observe,
      'guardian.request.vault.deposit.start',
      'created guardian vault deposit request',
      { contract_id : request.contract_id }
    )

    sub.on('message', (message : MessageData) => {
      switch (message.type) {
        case 'info': {
          const parsed = SHARED.base.str.parse(message.data)
          emit_info(observe, 'guardian.request.subscription.info', parsed)
          sub.emit('info', parsed)
          break
        }
        case 'reject': {
          const parsed = SHARED.base.str.parse(message.data)
          emit_warn(observe, 'guardian.request.vault.deposit.reject', 'guardian vault deposit request rejected', {
            reason : parsed
          })
          sub.emit('reject', parsed)
          break
        }
        case 'result': {
          const schema = SCHEMA.module.guard.response.vault_deposit
          const parsed = schema.parse(message.data)
          emit_debug(observe, 'guardian.request.vault.deposit.result', {
            vault_txid : parsed.vault_txid
          })
          sub.emit('result', parsed)
          break
        }
        case 'status': {
          const parsed = SHARED.base.str.parse(message.data)
          emit_info(observe, 'guardian.request.subscription.status', parsed)
          sub.emit('status', parsed)
          break
        }
      }
    })

    return sub
  }
}
