/**
 * @fileoverview Fan-out logger that dispatches each event to multiple sinks.
 *
 * Sinks are checked independently for level enablement, and a thrown error
 * from one sink does not affect siblings. The same LogEvent reference is
 * passed to every sink; sinks must treat events as immutable.
 */

import type {
  LogEvent,
  LogLevel,
  SdkLogger
} from './types.js'

export interface MultiplexLoggerOptions {
  sinks          : SdkLogger[]
  on_sink_error? : (error : unknown, sink_index : number, event : LogEvent) => void
}

export function create_multiplex_logger (
  options : MultiplexLoggerOptions
) : SdkLogger {
  const sinks         = options.sinks
  const on_sink_error = options.on_sink_error

  return {
    enabled (level : LogLevel) {
      for (const sink of sinks) {
        if (sink.enabled(level)) return true
      }
      return false
    },
    emit (event : LogEvent) {
      for (let i = 0; i < sinks.length; i++) {
        const sink = sinks[i]
        if (!sink.enabled(event.level)) continue
        try {
          sink.emit(event)
        } catch (error) {
          if (on_sink_error !== undefined) {
            on_sink_error(error, i, event)
          }
        }
      }
    }
  }
}
