/**
 * @fileoverview Observability context helpers.
 */

import { NOOP_LOGGER, NOOP_TRACER }    from './noop.js'
import { create_otel_tracer_adapter } from './otel.js'

import type {
  ObserveContext,
  ObservabilityOptions,
  SdkTracer
} from './types.js'

function is_observe_context (value : unknown) : value is ObserveContext {
  return (
    typeof value === 'object' &&
    value !== null &&
    'fields' in value &&
    'logger' in value &&
    'tracer' in value
  )
}

function get_tracer (
  options : ObservabilityOptions | undefined,
  logger  : ObserveContext['logger']
) : SdkTracer {
  if (options?.tracer) return options.tracer
  if (logger === NOOP_LOGGER) return NOOP_TRACER
  return create_otel_tracer_adapter({
    redact_sensitive : options?.redact_sensitive ?? true,
    unsafe_payloads  : options?.unsafe_payloads  ?? false
  })
}

export function get_observe_context (
  options?        : ObservabilityOptions | ObserveContext,
  default_fields  : Record<string, unknown> = {}
) : ObserveContext {
  if (is_observe_context(options)) {
    return {
      ...options,
      fields : { ...options.fields, ...default_fields }
    }
  }

  const logger = options?.logger ?? NOOP_LOGGER
  return {
    fields           : { ...options?.default_fields, ...default_fields },
    logger,
    span             : options?.span,
    tracer           : get_tracer(options, logger),
    redact_sensitive : options?.redact_sensitive ?? true,
    unsafe_payloads  : options?.unsafe_payloads  ?? false
  }
}

export function child_observe_context (
  context : ObserveContext,
  fields  : Record<string, unknown> = {},
  span    : ObserveContext['span'] = context.span
) : ObserveContext {
  return {
    ...context,
    fields : { ...context.fields, ...fields },
    span
  }
}

export function with_observe_span <T> (
  context : ObserveContext,
  name    : string,
  fields  : Record<string, unknown>,
  fn      : (scope : ObserveContext) => T
) : T {
  const span  = context.tracer.start_span(name, fields, context.span)
  const scope = child_observe_context(context, fields, span)

  try {
    const result = fn(scope)
    if (result instanceof Promise) {
      return result.then(value => {
        span.end()
        return value
      }).catch(error => {
        span.fail(error)
        throw error
      }) as T
    }
    span.end()
    return result
  } catch (error) {
    span.fail(error)
    throw error
  }
}
