/**
 * @fileoverview Validation of vault action configs against schemas and protocol invariants.
 */

import { Assert }          from '@vbyte/util'
import { DUST_LIMIT }      from '@/const.js'
import { VaultError }      from '@/lib/errors/index.js'
import { get_vault_terms } from '@ducat-unit/core/lib'

import * as SCHEMA from '@/schema/index.js'

import type { VaultActionConfig } from '@/types/index.js'

// ============================================
// CONSTANTS
// ============================================

/** Maximum reasonable fee rate in sats/vbyte. Prevents accidental overpayment. */
export const MAX_REASONABLE_FEE_RATE = 1000

export function validate_action_config (
  vault_config : VaultActionConfig,
) : void {
  // Define the vault action.
  const action = vault_config.vault_action
  // Define the schema.
  const schema = SCHEMA.vault.config
  // Assert the schema is valid.
  schema.parse(vault_config)

  // Universal sanity checks.
  assert_txfee_rate_reasonable(vault_config)

  // Assert the action is valid.
  switch (action) {
    case 'borrow':
      assert_vault_profile(vault_config)
      assert_postage(vault_config)
      assert_borrow_minimum(vault_config)
      assert_vault_state_for_action(vault_config)
      break
    case 'open':
      assert_funds(vault_config)
      assert_postage(vault_config)
      assert_borrow_minimum(vault_config)
      assert_deposit_minimum(vault_config)
      break
    case 'deposit':
      assert_vault_profile(vault_config)
      assert_funds(vault_config)
      break
    case 'repay':
      assert_vault_profile(vault_config)
      assert_postage(vault_config)
      assert_vault_state_for_action(vault_config)
      assert_repay_within_balance(vault_config)
      break
    case 'repo':
      assert_vault_profile(vault_config)
      assert_liquid_profiles(vault_config)
      break
    case 'trim':
      assert_vault_profile(vault_config)
      assert_liquid_profiles(vault_config)
      assert_no_funds(vault_config)
      break
    case 'withdraw':
      assert_vault_profile(vault_config)
      assert_no_funds(vault_config)
      assert_withdraw_within_balance(vault_config)
      break
    case 'close':
      assert_vault_profile(vault_config)
      assert_no_funds(vault_config)
      assert_vault_state_for_action(vault_config)
      break
    default:
      throw new VaultError(`unknown vault action: ${action}`)
  }
}

function assert_vault_profile (
  vault_config : VaultActionConfig
) : void {
  // Unpack the vault config.
  const { vault_profile } = vault_config
  // Assert the vault profile is defined.
  Assert.exists(vault_profile, 'vault profile is missing from vault context')
}

function assert_liquid_profiles (
  vault_config : VaultActionConfig
) : void {
  // Unpack the vault config.
  const { liquid_profiles } = vault_config
  // Assert the liquid profiles are defined.
  Assert.exists(liquid_profiles, 'liquid profiles are missing from vault context')
  // Assert the liquid profiles are not empty.
  Assert.ok(liquid_profiles.length > 0, 'liquid profiles are missing from vault context')
}

function assert_funds (
  vault_config : VaultActionConfig
) : void {
  // Unpack the vault config.
  const { vault_action, deposit_amount, txfee_reserve } = vault_config
  // Assert the deposit amount is defined.
  Assert.ok(Boolean(deposit_amount && deposit_amount > 0), `${vault_action} action must have a positive deposit amount`)
  // Assert the txfee reserve is defined.
  Assert.ok(Boolean(txfee_reserve  && txfee_reserve > 0),  `${vault_action} action must have txfee reserve greater than 0`)
}

function assert_no_funds (
  vault_config : VaultActionConfig
) : void {
  // Unpack the vault config.
  const { vault_action, deposit_amount, txfee_reserve } = vault_config
  // Assert the deposit amount is undefined.
  Assert.ok(!deposit_amount || deposit_amount === 0, `${vault_action} action must have no deposit amount`)
  // Assert the txfee reserve is undefined.
  Assert.ok(!txfee_reserve  || txfee_reserve  === 0,  `${vault_action} action must have no txfee reserve`)
}

function assert_postage (
  vault_config : VaultActionConfig
) : void {
  // Unpack the vault config.
  const { vault_action, unit_postage } = vault_config
  // If the unit postage is defined,
  if (unit_postage) {
    // Assert the unit postage is at least the dust limit (546 sats).
    Assert.ok(unit_postage >= DUST_LIMIT, `${vault_action} action must have unit postage at or above dust limit (${DUST_LIMIT})`)
  }
}

// ============================================
// AMOUNT SANITY CHECKS
// ============================================

/**
 * Check borrow amount against protocol minimum.
 */
function assert_borrow_minimum (
  vault_config : VaultActionConfig
) : void {
  const { borrow_amount, proto_profile } = vault_config
  // Skip if borrow_amount not provided or zero (borrowing is optional for some actions).
  if (!borrow_amount || borrow_amount === 0) return
  // Get the vault terms from the protocol profile.
  const vault_terms = get_vault_terms(proto_profile.proto_terms)
  // Assert the borrow amount is at least the protocol minimum.
  Assert.ok(
    borrow_amount >= vault_terms.unit_balance_min,
    `borrow amount ${borrow_amount} is below protocol minimum ${vault_terms.unit_balance_min}`
  )
}

/**
 * Check deposit amount against protocol minimum vault value.
 */
function assert_deposit_minimum (
  vault_config : VaultActionConfig
) : void {
  const { deposit_amount, proto_profile } = vault_config
  // Skip if deposit_amount not provided.
  if (!deposit_amount) return
  // Get the vault terms from the protocol profile.
  const vault_terms = get_vault_terms(proto_profile.proto_terms)
  // Assert the deposit amount is at least the protocol minimum vault value.
  Assert.ok(
    deposit_amount >= vault_terms.vault_value_min,
    `deposit amount ${deposit_amount} is below protocol minimum vault value ${vault_terms.vault_value_min}`
  )
}

/**
 * Check withdraw amount doesn't exceed vault balance.
 */
function assert_withdraw_within_balance (
  vault_config : VaultActionConfig
) : void {
  const { vault_action, vault_profile, withdraw_amount } = vault_config
  // Only check for withdraw actions with required fields.
  if (vault_action !== 'withdraw' || !vault_profile || !withdraw_amount) return
  // Assert the withdraw amount does not exceed the vault balance.
  Assert.ok(
    withdraw_amount <= vault_profile.vault_balance,
    `withdraw amount ${withdraw_amount} exceeds vault balance ${vault_profile.vault_balance}`
  )
}

/**
 * Check repay amount doesn't exceed unit balance.
 */
function assert_repay_within_balance (
  vault_config : VaultActionConfig
) : void {
  const { vault_action, vault_profile, repay_amount } = vault_config
  // Only check for repay actions with required fields.
  if (vault_action !== 'repay' || !vault_profile || !repay_amount) return
  // Assert the repay amount does not exceed the unit balance (debt).
  Assert.ok(
    repay_amount <= vault_profile.unit_balance,
    `repay amount ${repay_amount} exceeds unit balance ${vault_profile.unit_balance}`
  )
}

// ============================================
// STATE CONSISTENCY CHECKS
// ============================================

/**
 * Check vault state is appropriate for action.
 */
function assert_vault_state_for_action (
  vault_config : VaultActionConfig
) : void {
  const { vault_action, vault_profile } = vault_config
  // Skip if no vault profile provided.
  if (!vault_profile) return

  const is_encumbered = vault_profile.unit_balance > 0

  switch (vault_action) {
    case 'repay':
      // Cannot repay from a cleared vault (no debt to repay).
      Assert.ok(is_encumbered, 'cannot repay: vault has no debt')
      break
    case 'close':
      Assert.ok(!is_encumbered, 'cannot close: vault has debt')
      break
    case 'borrow':
      // Borrow allowed from either state (encumbered or cleared).
      break
    // These actions impose no debt-state constraint here; their state rules
    // are enforced downstream by the dedicated core verifiers. Enumerated
    // explicitly so unknown actions fail closed in the default branch.
    case 'open':
    case 'deposit':
    case 'withdraw':
    case 'repo':
    case 'trim':
    case 'liquidate':
      break
    default:
      // Fail closed on an unrecognized vault action.
      throw new VaultError(`assert_vault_state_for_action: unhandled vault action: ${vault_action}`)
  }

  if (vault_profile.vault_action === 'close') {
    throw new VaultError(`cannot ${vault_action}: vault is already closed`)
  }
}

// ============================================
// FEE RATE SANITY CHECKS
// ============================================

/**
 * Check fee rate is reasonable.
 */
function assert_txfee_rate_reasonable (
  vault_config : VaultActionConfig
) : void {
  const { txfee_rate } = vault_config
  // Assert the fee rate is not negative.
  Assert.ok(txfee_rate >= 0, 'txfee_rate cannot be negative')
  // Assert the fee rate is within reasonable bounds.
  Assert.ok(
    txfee_rate <= MAX_REASONABLE_FEE_RATE,
    `txfee_rate ${txfee_rate} exceeds reasonable maximum ${MAX_REASONABLE_FEE_RATE}`
  )
}
