/**
 * @fileoverview Runestone output builders for UNIT issue/repay flows.
 */

import { PSBT }                         from '@ducat-unit/core'
import { create_asset_transfer_script } from '@ducat-unit/core/lib'
import { TXMAP }                        from '@/const.js'

import type {
  AssetTransferConfig,
  PSBTOutput
} from '@ducat-unit/core'

import type {
  VaultBorrowRequestCtx,
  VaultOpenRequestCtx,
  VaultRepayRequestCtx
} from '@/types/index.js'

const UNIT_BURN_VOUT = TXMAP.UNIT_REPAY.VOUT.RDATA
const UNIT_XFER_VOUT = TXMAP.UNIT_ISSUE.VOUT.UNIT

/**
 * Create a PSBT output that is configured as a UNIT issuance utxo.
 *
 * The edict amount must be in smallest units (raw runes), not display units.
 * For vault open: issue the full unit_balance (already in smallest units)
 * For vault borrow: issue the credit amount (new balance - previous balance)
 *
 * @param vault_ctx : The vault context containing unit_balance and issue_account.
 * @returns A PSBT output containing the runestone edict.
 */
export function create_unit_issue_runestone (
  vault_ctx : VaultOpenRequestCtx | VaultBorrowRequestCtx
) : PSBTOutput {
  const { issue_account, unit_balance } = vault_ctx
  // Calculate the issue amount (in smallest units).
  // For open: full unit_balance (new vault has no previous debt)
  // For borrow: the credit amount (new - previous balance)
  let issue_amount : number
  if ('vault_profile' in vault_ctx && vault_ctx.vault_profile) {
    // Borrow: issue the difference between new and previous balance
    issue_amount = unit_balance - vault_ctx.vault_profile.unit_balance
  } else {
    // Open: issue the full balance
    issue_amount = unit_balance
  }
  // Create the asset transfer edict.
  const edict : AssetTransferConfig = {
    asset_id  : issue_account.asset_id,
    amount    : issue_amount,
    output    : UNIT_XFER_VOUT
  }
  // Get the script for the unit asset.
  const script = create_asset_transfer_script(edict)
  // Create the PSBT output.
  return PSBT.create_psbt_output({ value: 0, script_pk: script.hex })
}

/**
 * Create a PSBT output that is configured as a UNIT repayment utxo.
 *
 * The edict amount must be in smallest units (raw runes), not display units.
 * For repay: burn the debit amount (previous balance - new balance).
 *
 * @param vault_ctx : The vault context containing unit_balance and vault_profile.
 * @param route_change : When true, add a zero-amount routing edict for UNIT change.
 * @returns A PSBT output containing the runestone edict for burning.
 */
export function create_unit_burn_runestone (
  vault_ctx    : VaultRepayRequestCtx,
  route_change : boolean = false
) : PSBTOutput {
  // Unpack the vault context.
  const { unit_balance, vault_profile, vault_terms } = vault_ctx
  // Get the unit asset ID.
  const unit_asset_id = vault_terms.unit_asset_id
  // Calculate the burn amount (in smallest units).
  // The burn amount is the decrease in unit balance (previous - new).
  const burn_amount = vault_profile.unit_balance - unit_balance
  // Create the burn edict that sends repaid UNIT to OP_RETURN.
  const burn_edict : AssetTransferConfig = {
    asset_id  : unit_asset_id,
    amount    : burn_amount,
    output    : UNIT_BURN_VOUT
  }
  // Add an explicit change routing edict when repay inputs exceed burn amount.
  // This prevents residual UNIT from defaulting to pointer output 0 (connector).
  const edicts : AssetTransferConfig[] = [ burn_edict ]
  if (route_change) {
    edicts.push({
      asset_id  : unit_asset_id,
      amount    : 0,
      output    : TXMAP.UNIT_REPAY.VOUT.CHANGE
    })
  }
  // Get the script for the unit asset.
  const script = create_asset_transfer_script(edicts)
  // Create the PSBT output.
  return PSBT.create_psbt_output({ value: 0, script_pk: script.hex })
}
