/**
 * @fileoverview Vault Taproot input builders for open/update flows.
 */

import { Buff }   from '@vbyte/buff'
import { Assert } from '@vbyte/util/assert'
import { PSBT }   from '@ducat-unit/core'

import {
  create_vault_action_input,
  create_vault_connector_input,
  get_vault_profile_utxo,
  parse_cosigner_script
} from '@ducat-unit/core/lib'

import {
  create_connector_script,
  create_cleared_vault_script_tree,
  create_pledged_vault_script_tree,
  create_commit_script
} from '@/module/vault/lib/index.js'

import type {
  CoinUtxo,
  PSBTInput,
  VaultAction,
  VaultProfile,
} from '@ducat-unit/core'

import type {
  VaultOpenRequestCtx,
  VaultRequestCtx,
  VaultUpdateCtx
} from '@/types/index.js'

/**
 * Create the vault commit input used in the open flow commit transaction.
 * @param vault_ctx - Open request context with commit path parameters.
 * @param vault_utxo - Funding UTXO consumed by the commit input.
 * @returns PSBT tapscript input for commit-path spending.
 */
export function create_vault_commit_input (
  vault_ctx  : VaultOpenRequestCtx,
  vault_utxo : CoinUtxo
) : PSBTInput {
  // Build a single-leaf commit-path input tagged with the vault action.
  const scripts = [ create_commit_script(vault_ctx) ]
  const txinput = create_vault_action_input(vault_utxo, vault_ctx.vault_action)
  return PSBT.create_psbt_tapscript_input(scripts, txinput, { index : 0 })
}

/**
 * Create the connector input jointly controlled by client and active guardian.
 * @param vault_ctx - Request context with client and guardian pubkeys.
 * @param conn_utxo - Connector UTXO to spend.
 * @returns PSBT tapscript input for connector-path spending.
 */
export function create_vault_conn_input (
  vault_ctx : VaultRequestCtx,
  conn_utxo : CoinUtxo
) : PSBTInput {
  const { client_pubkey, guard_pubkey } = vault_ctx
  // Connector leaf enforces client + active guardian cosign.
  const scripts = [ create_connector_script(client_pubkey, guard_pubkey) ]
  const txinput = create_vault_connector_input(conn_utxo)
  return PSBT.create_psbt_tapscript_input(scripts, txinput, { index : 0 })
}

/**
 * Create a vault spend input for a cleared vault (zero UNIT balance).
 * @param vault_action - Vault action metadata encoded into sequence.
 * @param vault_profile - Existing vault profile to spend.
 * @param guard_pubkey - Active guardian pubkey used to select script branch.
 * @returns PSBT tapscript input spending the cleared vault branch.
 */
export function create_vault_cleared_input (
  vault_action  : VaultAction,
  vault_profile : VaultProfile,
  guard_pubkey  : string
) : PSBTInput {
  const { client_pubkey, guard_members, unit_balance } = vault_profile
  Assert.ok(unit_balance === 0, 'unit balance is not zero')
  const guard_idx = guard_members.indexOf(guard_pubkey)
  Assert.ok(guard_idx !== -1, 'active guardian is missing from allowed guardians list')
  // Cleared vault tree has one branch per guardian; select active guardian branch.
  const scripts = create_cleared_vault_script_tree(client_pubkey, guard_members)
  const selected_script = scripts[guard_idx]
  Assert.exists(selected_script, `script at guard index ${guard_idx} does not exist`)
  const parsed_script = parse_cosigner_script(new Buff(selected_script).hex)
  Assert.ok(
    parsed_script.guard_pubkey === guard_pubkey,
    `script at guard index ${guard_idx} contains unexpected pubkey: expected ${guard_pubkey}, got ${parsed_script.guard_pubkey}`
  )
  const utxo    = get_vault_profile_utxo(vault_profile)
  const txinput = create_vault_action_input(utxo, vault_action)
  return PSBT.create_psbt_tapscript_input(scripts, txinput, { index : guard_idx })
}

/**
 * Create a vault spend input for a pledged vault (non-zero UNIT balance).
 * @param vault_action - Vault action metadata encoded into sequence.
 * @param vault_profile - Existing vault profile to spend.
 * @param guard_pubkey - Active guardian pubkey used to select script branch.
 * @returns PSBT tapscript input spending the pledged vault branch.
 */
export function create_vault_pledged_input (
  vault_action  : VaultAction,
  vault_profile : VaultProfile,
  guard_pubkey  : string
) : PSBTInput {
  const { client_pubkey, guard_members, price_commits, unit_balance } = vault_profile
  Assert.ok(unit_balance > 0, 'unit balance is not greater than zero')
  const guard_idx = guard_members.indexOf(guard_pubkey)
  Assert.ok(guard_idx !== -1, 'active guardian is missing from allowed guardians list')
  Assert.exists(price_commits, 'price commits are missing from vault context')
  // Pledged tree layout: each guardian owns (1 + oracle_count) contiguous leaves.
  // The guardian connector leaf is the first entry in that guardian's segment.
  const script_idx = guard_idx * (1 + price_commits.length)
  const scripts = create_pledged_vault_script_tree(client_pubkey, guard_members, price_commits)
  const selected_script = scripts[script_idx]
  Assert.exists(selected_script, `script at index ${script_idx} does not exist`)
  const parsed_script = parse_cosigner_script(new Buff(selected_script).hex)
  Assert.ok(
    parsed_script.guard_pubkey === guard_pubkey,
    `script at index ${script_idx} contains unexpected pubkey: expected ${guard_pubkey}, got ${parsed_script.guard_pubkey}`
  )
  const utxo    = get_vault_profile_utxo(vault_profile)
  const txinput = create_vault_action_input(utxo, vault_action)
  return PSBT.create_psbt_tapscript_input(scripts, txinput, { index : script_idx })
}

/**
 * Dispatch to the correct vault spend input based on current UNIT balance.
 * @param vault_ctx - Update context with action, profile, and guardian key.
 * @returns PSBT input for either pledged or cleared vault spend path.
 */
export function create_vault_spend_input (
  vault_ctx  : VaultUpdateCtx
) : PSBTInput {
  const { guard_pubkey, vault_action, vault_profile } = vault_ctx
  // Cleared vs pledged spend path is determined by current debt state.
  return (vault_profile.unit_balance > 0)
    ? create_vault_pledged_input(vault_action, vault_profile, guard_pubkey)
    : create_vault_cleared_input(vault_action, vault_profile, guard_pubkey)
}
