/**
 * @fileoverview PSBT signing utilities for the ProtoWallet.
 *
 * Provides signing APIs that:
 * 1. Validate PSBT structure before signing
 * 2. Build signing manifests from PSBT inputs
 * 3. Support both single and batch signing operations
 *
 * ## Security Notes
 *
 * - PSBTs are validated before being passed to signing functions
 * - Manifests map addresses to input indices for selective signing
 * - Batch signing validates each PSBT independently
 *
 * @module wallet/lib/sign
 */

import { PSBT }            from '@ducat-unit/core'
import { ValidationError } from '@/lib/errors/index.js'
import { child_observe_context, emit_debug, emit_info } from '@/lib/observe/index.js'

import type { ProtoWallet }   from '../class/wallet.js'
import type { SignPSBTEntry } from '../types/connect.js'

/**
 * Validates a PSBT string before signing.
 * @param psbt - Base64 or hex encoded PSBT string
 * @throws {Error} If the PSBT is malformed or invalid
 */
function validate_psbt_structure (psbt : string) : void {
  // Attempt to decode the PSBT to verify its structure.
  // This will throw if the PSBT is malformed.
  try {
    PSBT.decode_psbt(psbt)
  } catch (err) {
    const message = err instanceof Error ? err.message : String(err)
    throw new ValidationError(`Invalid PSBT structure: ${message}`)
  }
}

/**
 * Build the single-PSBT signing API for a wallet: validates the PSBT structure,
 * fetches its manifest, and signs it through the wallet's connector, emitting
 * start/complete observe events.
 *
 * @param client - The proto wallet (connector, fetch, observe).
 * @returns An async `(psbt) => signed_psbt` signing function.
 */
export function sign_psbt_api (client : ProtoWallet) {
  const observe = child_observe_context(client.observe, { wallet_module : 'sign.psbt' })
  const sign_psbt = client.connector.sign.psbt(client)
  return async (psbt : string) : Promise<string> => {
    emit_info(observe, 'wallet.sign.psbt.start', 'signing single PSBT', {
      psbt_length : psbt.length
    })
    // Validate PSBT structure before processing.
    validate_psbt_structure(psbt)
    const manifest = await client.fetch.manifest(psbt)
    const signed = await sign_psbt(psbt, manifest)
    emit_debug(observe, 'wallet.sign.psbt.complete', {
      manifest_key_count : Object.keys(manifest).length,
      psbt_length        : psbt.length,
      signed_length      : signed.length
    })
    return signed
  }
}

/** Create batch signing API with connector override and local fallback. */
export function sign_batch_api (client : ProtoWallet) {
  const observe = child_observe_context(client.observe, { wallet_module : 'sign.batch' })
  const batch_method = client.connector.sign.batch
  const sign_batch   = (batch_method !== undefined)
    ? batch_method(client)
    : default_batch_method(client)
  return async (psbts : string[]) : Promise<string[]> => {
    emit_info(observe, 'wallet.sign.batch.start', 'signing PSBT batch', {
      psbt_count : psbts.length
    })
    const entries : SignPSBTEntry[] = []
    for (const psbt of psbts) {
      // Validate each PSBT structure before processing.
      validate_psbt_structure(psbt)
      const manifest = await client.fetch.manifest(psbt)
      entries.push([ psbt, manifest ])
    }
    const signed = await sign_batch(entries)
    emit_debug(observe, 'wallet.sign.batch.complete', {
      psbt_count         : psbts.length,
      signed_count       : signed.length,
      total_psbt_length  : psbts.reduce((sum, item) => sum + item.length, 0)
    })
    return signed
  }
}

/** Default batch signer that executes single-sign calls sequentially. */
function default_batch_method (client : ProtoWallet) {
  const sign_psbt = client.connector.sign.psbt(client)
  return async (entries : SignPSBTEntry[]) : Promise<string[]> => {
    const signed : string[] = []
    for (const [ psbt, manifest ] of entries) {
      const signed_psbt = await sign_psbt(psbt, manifest)
      signed.push(signed_psbt)
    }
    return signed
  }
}
