/**
 * @fileoverview Liquidation utilities for the repo (repossession) module.
 *
 * ## Liquidation Overview
 *
 * When a vault's collateral ratio falls below the protocol minimum, it becomes
 * eligible for liquidation. This protects the protocol by ensuring UNIT tokens
 * remain adequately backed by BTC collateral.
 *
 * ## Liquidation Triggers
 *
 * A vault is liquidated when:
 *   collateral_ratio = (vault_sats_in_btc × oracle_price) / unit_balance
 *   collateral_ratio < vault_ratio_min (typically 1.5 or 150%)
 *
 * ## Price Commits and Threshold Hashes
 *
 * Liquidation scripts use "threshold hashes" (thold_hash) derived from oracle
 * price commits. These hashes prove that a specific price point was reached,
 * enabling the liquidation script to be spent. The thold_hash is a HASH160 of
 * the threshold key (thold_key) that unlocks the liquidation spending path.
 *
 * ## Script Structure
 *
 * Vault outputs use Taproot with multiple spending paths:
 * - Index 0: Normal spending path (owner + guardian co-signature)
 * - Index 1+: Liquidation paths (one per guardian × threshold combination)
 *
 * The `get_liquid_script_idx` function calculates which script index corresponds
 * to a specific guardian and threshold combination.
 */

import { Buff }    from '@vbyte/buff'
import { Assert }  from '@vbyte/util'
import { hash160 } from '@vbyte/crypto/hash'
import { parse_liquidation_script } from '@ducat-unit/core/lib'

import type { LiquidVaultProfile, PriceCommitData } from '@ducat-unit/core'

/**
 * Finds the index of a price commit matching the given threshold key.
 *
 * @param price_commits - Array of price commit data from the vault
 * @param thold_key - Threshold key (hex string) to search for
 * @returns Index of the matching price commit, or null if not found
 */
export function find_price_commit_idx (
  price_commits : PriceCommitData[],
  thold_key     : string
) : number | null {
  // Match is performed on HASH160(thold_key) since scripts commit to the hash,
  // not the cleartext threshold key itself.
  // Get the hash of the commit key.
  const ref_hash = hash160(thold_key).hex
  // Find the index of the commit hash.
  const idx = price_commits.findIndex(commit => commit.thold_hash === ref_hash)
  // Return the index of the commit hash, or null if not found.
  return idx !== -1 ? idx : null
}

/**
 * Calculates the script index for a liquidation spending path.
 *
 * The Taproot tree structure places liquidation scripts after the cosign script:
 *   Script 0: Cosign path (normal spending)
 *   Script 1+: Liquidation paths organized by (guardian_index × threshold_count + threshold_index)
 *
 * @param guard_index - Index of the guardian in the MPC group (0-based)
 * @param thold_count - Total number of threshold levels
 * @param thold_idx - Index of the specific threshold (0-based)
 * @returns The script index in the Taproot tree
 */
export function get_liquid_script_idx (
  guard_index : number,
  thold_count : number,
  thold_idx   : number
) : number {
  // Layout: [cosign(0), g0-th0, g0-th1, ..., g1-th0, g1-th1, ...].
  // Set the cosign script offset.
  const COSIGN_SCRIPT_OFFSET = 1
  // Calculate the script index.
  return (guard_index * thold_count) + COSIGN_SCRIPT_OFFSET + thold_idx
}

/**
 * Extracts the threshold hash from a price commit at the given index.
 *
 * @param commits - Array of price commit data
 * @param index - Index of the commit to extract from
 * @returns Threshold hash as bytes (20 bytes, HASH160 format)
 * @throws If the threshold hash is missing from the price commit
 */
export function get_price_commit_thold_hash (
  commits : PriceCommitData[],
  index   : number
) : Uint8Array {
  // Get the commit hash.
  const thold_hash = commits[index].thold_hash
  // Assert that the commit hash exists.
  Assert.exists(thold_hash, 'thold hash is missing from price commit')
  // Convert the commit hash to bytes.
  return Buff.hex(thold_hash)
}

/**
 * Sums the claimed satoshi amounts from liquidated vault profiles.
 *
 * @param liquid_profiles - Array of liquidated vault profiles
 * @returns Total satoshis claimed across all liquidated vaults
 */
export function get_claimed_sats_amount (
  liquid_profiles : LiquidVaultProfile[]
) : number {
  // Return the claimed sats amount.
  return liquid_profiles.reduce((acc, profile) => acc + profile.claimed_sats, 0)
}

/**
 * Verifies that a liquidation script contains the expected threshold hash.
 *
 * This ensures the script can be spent with the provided threshold preimage.
 *
 * @param scripts - Array of spending scripts from the Taproot tree
 * @param script_idx - Index of the liquidation script to verify
 * @param thold_bytes - Expected threshold hash (20 bytes)
 * @throws If the script doesn't exist at the index
 * @throws If the script doesn't contain the threshold hash
 */
export function verify_liquid_script (
  scripts     : Uint8Array[],
  script_idx  : number,
  thold_bytes : Uint8Array
) : void {
  // This is a structural guard to catch mismatched (guardian, threshold)
  // index calculations before PSBT construction proceeds.
  // Get the script from the array.
  const script = scripts.at(script_idx)
  // Assert that the script exists.
  Assert.exists(script, `script does not exist at index: ${script_idx}`)
  // Get the thold hash.
  const thold_hex  = Buff.u8a(thold_bytes, 20).hex
  // Parse and verify exact liquidation script template.
  const parsed_script = parse_liquidation_script(Buff.u8a(script).hex)
  Assert.ok(parsed_script.liquid_hash === thold_hex, 'liquidation script threshold hash mismatch')
}
