/**
 * @fileoverview Builds the action context (counts and balances) for a vault action config.
 */

import {
  get_vault_guardian_count,
  get_price_oracle_count,
  tabulate_reserve_balance,
  tabulate_unit_balance
} from '@/lib/index.js'

import type {
  VaultActionConfig,
  VaultActionContext
} from '@/types/index.js'

/**
 * Create a context object for a vault action.
 *
 * @param action_config - The action config.
 * @returns The vault action context.
 */
export function create_vault_action_context (
  action_config : VaultActionConfig
) : VaultActionContext {
  // Calculate the guardian count.
  const guardian_count  = get_vault_guardian_count(action_config)
  // Calculate the oracle count.
  const oracle_count    = get_price_oracle_count(action_config)
  // Calculate the liquid count.
  const liquid_count    = action_config.liquid_profiles?.length ?? 0
  // Calculate the reserve balance.
  const reserve_balance = tabulate_reserve_balance(action_config)
  // Calculate the unit balance.
  const unit_balance    = tabulate_unit_balance(action_config)
  // Return the vault action context.
  return { guardian_count, liquid_count, oracle_count, reserve_balance, unit_balance }
}
