/**
 * @fileoverview Validator API fetch helpers for witness commits (all, latest, history).
 */

import { Fetch, Resolve }          from '@vbyte/util'
import {
  validate_fetch_list_response,
  validate_fetch_response,
  safe_path_segment
} from './util.js'
import * as SHARED                 from '@ducat-unit/core/schema'

import type { WitnessRecord } from '@ducat-unit/core'

/**
 * Resolve latest-commit endpoint path for commit root ids and legacy
 * txid-style keys. Validator serves both through the same
 * `/api/commit/:key/latest` route shape.
 */
function resolve_commit_latest_path (key : string) : string {
  return `/api/commit/${safe_path_segment(key, 'commit key')}/latest`
}

/**
 * Resolve commit-history endpoint path for commit root ids and legacy
 * txid-style keys. Validator serves both through the same
 * `/api/commit/:key/history` route shape.
 */
function resolve_commit_history_path (key : string) : string {
  return `/api/commit/${safe_path_segment(key, 'commit key')}/history`
}

/**
 * Fetches global commit history from the validator API
 * @param host_url - Base URL of the validator API server
 * @param page_size - Maximum number of records to return
 * @param cursor   - Opaque cursor for the next page
 * @returns Array of witness record data or error response
 */
export async function fetch_commit_all (
  host_url : string,
  page_size? : number,
  cursor?  : string
) : Promise<Resolve.Type<WitnessRecord[]>> {
  const url = new URL(`${host_url}/api/commit/history`)
  if (page_size !== undefined) url.searchParams.set('page_size', String(page_size))
  if (cursor !== undefined) url.searchParams.set('cursor', cursor)
  const res = await Fetch.json(url.toString())
  if (!res.ok) return res
  return validate_fetch_list_response(
    SHARED.witness.record.array(),
    res.data,
    'global commit history validation failed'
  )
}

/**
 * Fetches the latest commit record by root ID from the validator API
 * @param host_url - Base URL of the validator API server
 * @param root_id  - The commit root ID
 * @returns Witness record data or error response
 */
export async function fetch_commit_latest (
  host_url : string,
  root_id  : string
) : Promise<Resolve.Type<WitnessRecord>> {
  const url = `${host_url}${resolve_commit_latest_path(root_id)}`
  const res = await Fetch.json(url)
  if (!res.ok) return res
  return validate_fetch_response(
    SHARED.witness.record,
    res.data,
    'commit record validation failed'
  )
}

/**
 * Fetches commit history by root ID from the validator API
 * @param host_url - Base URL of the validator API server
 * @param root_id  - The commit root ID
 * @param page_size - Maximum number of records to return
 * @param cursor   - Opaque cursor for the next page
 * @returns Array of witness record data or error response
 */
export async function fetch_commit_history (
  host_url : string,
  root_id  : string,
  page_size? : number,
  cursor?  : string
) : Promise<Resolve.Type<WitnessRecord[]>> {
  const url = new URL(`${host_url}${resolve_commit_history_path(root_id)}`)
  if (page_size !== undefined) url.searchParams.set('page_size', String(page_size))
  if (cursor !== undefined) url.searchParams.set('cursor', cursor)
  const res = await Fetch.json(url.toString())
  if (!res.ok) return res
  return validate_fetch_list_response(
    SHARED.witness.record.array(),
    res.data,
    'commit history validation failed'
  )
}
