/**
 * @fileoverview PSBT utilities for vault transactions.
 *
 * Provides helper functions for working with PSBTs in vault operations:
 * - Input code extraction from sequence data
 * - Total calculation for inputs/outputs/fees (using BigInt for precision)
 * - Input finalization for spending, co-signing, and liquidation paths
 *
 * ## Security Notes
 *
 * - All amount calculations use BigInt to prevent precision loss
 * - Array access is validated before element retrieval
 * - Dust limit enforcement on all outputs
 *
 * @module vault/lib/psbt
 */

import { Assert }               from '@vbyte/util'
import { Buff }                 from '@vbyte/buff'
import { get_lock_script_type } from '@vbyte/btc-dev/script'
import { PSBT }                 from '@ducat-unit/core'
import { decode_sequence }      from '@ducat-unit/core/lib'

import {
  BIGINT,
  DUST_LIMIT,
  COSIGN_CODES,
  LIQUID_CODES
} from '@/const.js'

import type { PSBTData, PSBTInput } from '@ducat-unit/core'
import type {
  SighashEntry
} from '@ducat-unit/core'

interface PSBTTotals {
  txin_total : bigint
  vout_total : bigint
  fees_total : bigint
}

/** Read metadata sequence code from PSBT input when present. */
export function get_input_code (input : PSBTInput) : number | null {
  // Skip if the input sequence is not set.
  if (!input.sequence) return null
  // Decode the sequence data.
  const sdata = decode_sequence(input.sequence)
  // Skip if the sequence data is not a metadata input.
  if (sdata.type !== 'metadata') return null
  // Return the sequence data.
  return sdata.code
}

/** Calculate total input/output values and implied fees for a PSBT. */
export function calc_psbt_totals (pdata : PSBTData) : PSBTTotals {
  // Initialize the total input and output values using BigInt for precision safety.
  let txin_total = BIGINT._0
  let vout_total = BIGINT._0
  // Iterate over the outputs in the PSBT.
  for (let idx = 0; idx < pdata.outputsLength; idx++) {
    const vout = pdata.getOutput(idx)
    // Assert that the amount and script key exist.
    Assert.exists(vout.amount, `amount not set for vout index: ${idx}`)
    Assert.exists(vout.script, `script key does not exist for vout index: ${idx}`)
    // Assert that the amount is not below the dust limit.
    Assert.ok(vout.amount >= BigInt(DUST_LIMIT), `amount is below the dust limit: ${vout.amount} < ${DUST_LIMIT}`)
    // Add the amount to the total output value.
    vout_total += vout.amount
  }

  // Iterate over the inputs in the PSBT.
  for (let idx = 0; idx < pdata.inputsLength; idx++) {
    // Fetch the input.
    const txin = pdata.getInput(idx)
    // Assert that the non-witness UTXO is not set.
    Assert.ok(txin.nonWitnessUtxo === undefined, `legacy UTXO is not supported`)
    // Fetch the amount from the witness UTXO
    const amount = txin.witnessUtxo?.amount
    // Assert that the witness UTXO or non-witness UTXO exists.
    Assert.exists(amount, `prevout does not exist for txin index: ${idx}`)
    // Assert that the amount exists.
    Assert.exists(txin.witnessUtxo?.amount, `amount not set for txin index: ${idx}`)
    // Add the amount to the total input value.
    txin_total += amount
  }
  // Calculate the total fees.
  const fees_total = txin_total - vout_total
  // Return the totals.
  return { txin_total, vout_total, fees_total }
}

/** Finalize standard spending inputs (legacy/segwit/taproot key path). */
export function finalize_spending_inputs (pdata : PSBTData) : void {
  // For each input in the PSBT,
  for (let i = 0; i < pdata.inputsLength; i++) {
    // Extract the input.
    const pvin = pdata.getInput(i)
    // If the input does not have a witness UTXO, skip it.
    if (!pvin.witnessUtxo) continue
    // Get the prevout script.
    const script = pvin.witnessUtxo.script
    // Get the script type.
    const type = get_lock_script_type(script)
    // If the script type is null, skip it.
    if (type === null) continue
    // If the script type is a P2SH, P2WPKH, or P2WSH,
    if (type === 'p2sh') {
      PSBT.finalize_legacy_input(pdata, i)
    // Else, if the script type is a P2WPKH,
    } else if (type === 'p2wpkh') {
      PSBT.finalize_p2wpkh_input(pdata, i)
    // Else, if the script type is a P2TR,
    } else if (type === 'p2tr') {
      // P2TR inputs with tapLeafScript are Taproot script path spends (e.g., vault
      // co-signing or liquidation paths). These require special finalization with
      // guardian signatures and are handled by finalize_cosign_inputs() or
      // finalize_liquid_inputs() instead.
      if (pvin.tapLeafScript !== undefined) continue
      // Finalize simple P2TR key path spend.
      PSBT.finalize_p2tr_input(pdata, i)
    }
  }
}

/**
 * Finalize guardian co-signed script-path inputs within the PSBT.
 * @param pdata : PSBT object.
 */
export function finalize_cosign_inputs (
  pdata : PSBTData
) : void {
  for (let idx = 0; idx < pdata.inputsLength; idx++) {
    // Fetch the input.
    const pvin = pdata.getInput(idx)
    // Fetch the input code.
    const code = get_input_code(pvin)
    // Skip if the input code is null.
    if (code === null) continue
    // Skip if the sequence data is not a guardian co-signed input.
    if (!COSIGN_CODES.includes(code)) continue
    // Validate array lengths before accessing elements.
    Assert.ok(pvin.tapLeafScript !== undefined && pvin.tapLeafScript.length > 0, 'tapLeafScript array is empty or missing')
    Assert.ok(pvin.tapScriptSig !== undefined && pvin.tapScriptSig.length > 0, 'tapScriptSig array is empty or missing')
    // Fetch the first tapleaf script for the input.
    const tap_data = pvin.tapLeafScript[0]
    // Fetch the first tapscript signature for the input.
    const sig_data = pvin.tapScriptSig[0]
    // Validate tap_data structure before accessing nested properties.
    Assert.ok(tap_data[1] !== undefined && tap_data[1].length > 0, 'tapLeaf script data is empty')
    // Parse the script bytes from the PSBT tapleaf input.
    const script = tap_data[1].slice(0, -1)
    // Create the control block from the PSBT input data.
    const cblock = PSBT.encode_psbt_cblock(tap_data[0])
    // Update the vault prevout input with a finalized script witness.
    pdata.updateInput(idx, {
      finalScriptWitness : [ sig_data[1], script, cblock ]
    })
  }
}

/** Finalize liquidation script-path inputs using hash preimage witnesses. */
export function finalize_liquid_inputs (
  pdata : PSBTData
) : void {
  for (let idx = 0; idx < pdata.inputsLength; idx++) {
    // Fetch the input.
    const pvin = pdata.getInput(idx)
    // Fetch the input code.
    const code = get_input_code(pvin)
    // Skip if the input code is null.
    if (code === null) continue
    // Skip if the input code is not a liquid input.
    if (!LIQUID_CODES.includes(code)) continue
    // Validate array lengths before accessing elements.
    Assert.ok(pvin.tapLeafScript !== undefined && pvin.tapLeafScript.length > 0, 'tapLeafScript array is empty or missing')
    Assert.ok(pvin.hash160 !== undefined && pvin.hash160.length > 0, 'hash160 array is empty or missing')
    // Fetch the first tapleaf script for the input.
    const tap_data = pvin.tapLeafScript[0]
    // Fetch the first hash pre-image for the input.
    const hash_data = pvin.hash160[0]
    // Validate tap_data structure before accessing nested properties.
    Assert.ok(tap_data[1] !== undefined && tap_data[1].length > 0, 'tapLeaf script data is empty')
    // Parse the script bytes from the PSBT tapleaf input.
    const script = tap_data[1].slice(0, -1)
    // Create the control block from the PSBT input data.
    const cblock = PSBT.encode_psbt_cblock(tap_data[0])
    // Update the vault prevout input with a finalized script witness.
    pdata.updateInput(idx, {
      finalScriptWitness : [ hash_data[1], script, cblock ]
    })
  }
}

/** Extract guardian signing sighashes for script-path vault inputs. */
export function extract_guardian_sighashes (
  pdata : PSBTData
) : SighashEntry[] {
  const prevouts = PSBT.get_psbt_prevouts(pdata)
  const sighashes : SighashEntry[] = []

  for (let idx = 0; idx < pdata.inputsLength; idx++) {
    const pvin = pdata.getInput(idx)
    const code = get_input_code(pvin)
    if (code === null) continue
    if (!COSIGN_CODES.includes(code) && !LIQUID_CODES.includes(code)) continue

    Assert.ok(pvin.tapLeafScript !== undefined && pvin.tapLeafScript.length > 0, 'tapLeafScript array is empty or missing')
    const tap_data = pvin.tapLeafScript[0]
    Assert.ok(tap_data[1] !== undefined && tap_data[1].length > 0, 'tapLeaf script data is empty')
    const script = tap_data[1].slice(0, -1)
    const sighash = pdata.preimageWitnessV1(idx, prevouts.scripts, 0, prevouts.amounts, undefined, script)

    sighashes.push({
      idx,
      sighash : new Buff(sighash).hex,
      sigflag : 0
    })
  }

  return sighashes
}
