/**
 * @fileoverview Schema validation helpers that throw ValidationError on invalid data.
 */

import { ValidationError }           from '@/lib/errors/index.js'
import { format_validation_message } from './util.js'
import type { ZodSchema }            from 'zod'

import type { ValidationResult, ValidateOptions } from './types.js'

/**
 * Validates data against a Zod schema and throws ValidationError on failure.
 * Use this when you want to halt execution on invalid data.
 *
 * @param schema       - Zod schema to validate against
 * @param data         - Data to validate
 * @param error_prefix - Optional prefix for error message
 * @returns Parsed and typed data
 * @throws ValidationError if validation fails
 */
export function validate<T> (
  schema       : ZodSchema<T>,
  data         : unknown,
  error_prefix?: string
): T {
  const parsed = schema.safeParse(data)
  if (!parsed.success) {
    const message = format_validation_message(parsed.error, error_prefix)
    throw new ValidationError(message, { zod_error: parsed.error })
  }
  return parsed.data
}

/**
 * Validates data against a Zod schema and returns a result object.
 * Use this when you need to handle validation failures without exceptions.
 *
 * @param schema       - Zod schema to validate against
 * @param data         - Data to validate
 * @param options      - Validation options
 * @returns ValidationResult with either data or error details
 */
export function safe_validate<T> (
  schema  : ZodSchema<T>,
  data    : unknown,
  options : ValidateOptions = {}
): ValidationResult<T> {
  const parsed = schema.safeParse(data)
  if (!parsed.success) {
    const message = format_validation_message(parsed.error, options.error_prefix)
    return { ok: false, error: parsed.error, message }
  }
  return { ok: true, data: parsed.data }
}

/**
 * Type assertion wrapper for validation. Validates and narrows the type.
 * Use this when you need TypeScript to narrow the type after validation.
 *
 * @param schema       - Zod schema to validate against
 * @param data         - Data to validate
 * @param error_prefix - Optional prefix for error message
 * @throws ValidationError if validation fails
 */
export function assert_valid<T> (
  schema       : ZodSchema<T>,
  data         : unknown,
  error_prefix?: string
): asserts data is T {
  validate(schema, data, error_prefix)
}
