/**
 * @fileoverview Vault Borrow API - Issue additional UNIT debt against vault collateral.
 *
 * The borrow action allows vault owners to issue more UNIT tokens against their
 * existing collateral. This increases the debt position while maintaining the
 * same collateral amount.
 *
 * ## Two-Transaction Pattern
 *
 * Borrow uses the two-PSBT pattern:
 * 1. **Issue TX (PSBT 1)**: Issues new UNIT via Runestone protocol
 * 2. **Vault TX (PSBT 2)**: Updates vault state with guardian co-signature
 *
 * ## Collateral Requirements
 *
 * The borrow amount is constrained by the minimum collateral ratio. The vault
 * must maintain at least 150% (or protocol-configured minimum) collateral ratio
 * after borrowing.
 *
 * ## Usage
 *
 * ```typescript
 * import { VaultBorrowAPI } from '@ducat-unit/client-sdk/vault'
 *
 * const ctx = VaultBorrowAPI.create_ctx(config)
 * const psbts = VaultBorrowAPI.create_psbts(ctx)
 * const signed = await wallet.sign.batch(psbts)
 * const request = VaultBorrowAPI.create_request(ctx, signed)
 * ```
 *
 * @module vault/api/borrow
 */

import { Assert }               from '@vbyte/util'
import { get_txid }             from '@vbyte/btc-dev/tx'
import { PSBT }                 from '@ducat-unit/core'
import { get_coin_total_value } from '@ducat-unit/core/lib'
import { PSBT_CONFIG, TXMAP }   from '@/const.js'
import {
  emit_debug,
  emit_info,
  with_observe_span
} from '@/lib/observe/index.js'

import {
  create_issue_account_output,
  create_unit_change_output,
  create_unit_spend_input,
  create_sats_change_output,
  create_vault_connector_vout,
  create_vault_return_output,
  create_vault_output,
  finalize_cosign_inputs,
  create_unit_issue_runestone,
  create_vault_conn_input,
  finalize_spending_inputs,
  create_issue_change_output,
  verify_vault_request_psbt,
  verify_vault_action_rules,
  create_vault_ctx,
  create_vault_request,
  create_unit_account_input,
  create_vault_spend_input,
  validate_vault_borrow_config,
  validate_vault_borrow_request
} from '../lib/index.js'

import type {
  VaultBorrowRequest
} from '@ducat-unit/core'
import type {
  VaultBorrowRequestConfig,
  VaultBorrowRequestCtx
} from '@/types/index.js'

/**
 * Define the indexes for our transaction input/output types.
 */
const ISSUE_UNIT_VOUT = TXMAP.UNIT_ISSUE.VOUT.UNIT
const ISSUE_CONN_VOUT = TXMAP.UNIT_ISSUE.VOUT.CONN

/**
 * Create a context object for a Vault Borrow action.
 *
 * @param vault_config - User-provided vault-borrow configuration.
 * @returns Validated vault-borrow request context.
 */
export function create_vault_borrow_ctx (vault_config : VaultBorrowRequestConfig) : VaultBorrowRequestCtx {
  // Validate the configuration for a vault borrow action.
  validate_vault_borrow_config(vault_config)
  // Return the vault context object.
  return create_vault_ctx(vault_config)
}

/**
 * Create the UNIT issue/funding PSBT for vault-borrow.
 *
 * @param vault_ctx - Vault-borrow request context.
 * @returns Encoded issue PSBT.
 */
export function create_vault_borrow_psbt1 (
  vault_ctx : VaultBorrowRequestCtx
) {
  return with_observe_span(
    vault_ctx.observe,
    'vault.borrow.create_issue_psbt',
    { fund_input_count : vault_ctx.fund_inputs.length },
    scope => {
      const { fund_inputs, issue_account, unit_postage } = vault_ctx
      const fund_value = get_coin_total_value(fund_inputs)
      const conn_value = fund_value - unit_postage
      const pdata = PSBT.create_psbt(PSBT_CONFIG)
      // issue output
      pdata.addOutput(create_issue_account_output(vault_ctx))
      // issue change
      pdata.addOutput(create_issue_change_output(vault_ctx))
      // vault connector
      pdata.addOutput(create_vault_connector_vout(vault_ctx, conn_value))
      // OP_RETURN data
      pdata.addOutput(create_unit_issue_runestone(vault_ctx))
      // issue input
      pdata.addInput(create_unit_account_input(issue_account))
      // fund inputs
      for (const utxo of fund_inputs) {
        pdata.addInput(PSBT.create_psbt_input(utxo))
      }
      PSBT.assert_is_funded(pdata)
      const psbt = PSBT.encode_psbt(pdata)
      emit_info(scope, 'vault.borrow.psbt.issue.created', 'created vault borrow issue PSBT', {
        psbt_length : psbt.length
      })
      return psbt
    }
  )
}

/**
 * Create the vault-state update PSBT for vault-borrow.
 *
 * @param vault_ctx - Vault-borrow request context.
 * @param issue_psbt - Encoded issue PSBT from phase 1.
 * @returns Encoded vault PSBT.
 */
export function create_vault_borrow_psbt2 (
  vault_ctx  : VaultBorrowRequestCtx,
  issue_psbt : string | Uint8Array
) {
  return with_observe_span(
    vault_ctx.observe,
    'vault.borrow.create_vault_psbt',
    { issue_psbt_length : typeof issue_psbt === 'string' ? issue_psbt.length : issue_psbt.length },
    scope => {
      const { change_value, unit_balance, vault_balance } = vault_ctx
      const issue_pdata = PSBT.parse_psbt(issue_psbt)
      const unit_utxo   = PSBT.extract_utxo(issue_pdata, ISSUE_UNIT_VOUT)
      const conn_utxo   = PSBT.extract_utxo(issue_pdata, ISSUE_CONN_VOUT)
      const pdata = PSBT.create_psbt(PSBT_CONFIG)
      // unit change
      pdata.addOutput(create_unit_change_output(vault_ctx))
      // vault output
      pdata.addOutput(create_vault_output(vault_ctx, unit_balance, vault_balance))
      // sats change
      if (change_value > 0) {
        pdata.addOutput(create_sats_change_output(vault_ctx, change_value))
      }
      // OP_RETURN data
      pdata.addOutput(create_vault_return_output(vault_ctx))
      // unit input
      pdata.addInput(create_unit_spend_input(unit_utxo))
      // vault input
      pdata.addInput(create_vault_spend_input(vault_ctx))
      // connector input
      pdata.addInput(create_vault_conn_input(vault_ctx, conn_utxo))
      PSBT.assert_is_funded(pdata)
      const psbt = PSBT.encode_psbt(pdata)
      emit_info(scope, 'vault.borrow.psbt.vault.created', 'created vault borrow vault PSBT', {
        psbt_length : psbt.length
      })
      return psbt
    }
  )
}

/**
 * Create both PSBTs required for vault-borrow.
 *
 * @param vault_ctx - Vault-borrow request context.
 * @returns Tuple-like array `[issuePsbt, vaultPsbt]`.
 */
export function create_vault_borrow_psbts (
  vault_ctx : VaultBorrowRequestCtx
) : string[] {
  return with_observe_span(
    vault_ctx.observe,
    'vault.borrow.create_psbts',
    {},
    scope => {
      const issue_psbt = create_vault_borrow_psbt1(vault_ctx)
      const vault_psbt = create_vault_borrow_psbt2(vault_ctx, issue_psbt)
      emit_debug(scope, 'vault.borrow.create_psbts.complete', {
        issue_psbt_length : issue_psbt.length,
        vault_psbt_length : vault_psbt.length
      })
      return [ issue_psbt, vault_psbt ]
    }
  )
}

/**
 * Create a signed guardian request payload for vault-borrow.
 *
 * @param vault_ctx - Vault-borrow request context.
 * @param vault_psbts - Signed PSBT package `[issue, vault]`.
 * @returns Validated vault-borrow request payload.
 */
export function create_vault_borrow_request (
  vault_ctx   : VaultBorrowRequestCtx,
  vault_psbts : string[]
) : VaultBorrowRequest {
  return with_observe_span(
    vault_ctx.observe,
    'vault.borrow.create_request',
    { signed_psbt_count : vault_psbts.length },
    scope => {
      const [ signed_issue_psbt, signed_vault_psbt ] = vault_psbts
      Assert.exists(signed_issue_psbt, 'issue PSBT is undefined')
      Assert.exists(signed_vault_psbt, 'vault PSBT is undefined')
      const context = create_vault_request(vault_ctx)
      const issue_pdata = PSBT.parse_psbt(signed_issue_psbt)
      const vault_pdata = PSBT.parse_psbt(signed_vault_psbt)
      finalize_spending_inputs(issue_pdata)
      finalize_cosign_inputs(vault_pdata)
      verify_vault_request_psbt(issue_pdata, 0)
      verify_vault_request_psbt(vault_pdata, vault_ctx.txfee_rate, {
        ...vault_ctx.validation_options,
        asset_pdata: issue_pdata,
        observe: vault_ctx.observe
      })
      const issue_txid = get_txid(issue_pdata.hex)
      const vault_txid = get_txid(vault_pdata.hex)
      verify_vault_action_rules(vault_ctx, vault_txid)
      const issue_psbt = PSBT.encode_psbt(issue_pdata)
      const vault_psbt = PSBT.encode_psbt(vault_pdata)
      const request = { ...context, issue_psbt, issue_txid, vault_psbt, vault_txid }
      validate_vault_borrow_request(request)
      emit_info(scope, 'vault.borrow.request.created', 'created vault borrow guardian request', {
        issue_txid,
        vault_txid
      })
      return request
    }
  )
}

/**
 * Export the API for the vault borrow action.
 */
export namespace VaultBorrowAPI {
  export const create_ctx     = create_vault_borrow_ctx
  export const create_psbts   = create_vault_borrow_psbts
  export const create_request = create_vault_borrow_request
}
