/**
 * @fileoverview UNIT-account output builders for vault request flows.
 */

import { P2TR }                   from '@vbyte/btc-dev/address'
import { Assert }                 from '@vbyte/util'
import { PSBT }                   from '@ducat-unit/core'
import { get_asset_account_utxo } from '@ducat-unit/core/lib'
import { assert_dust_limit }      from '@ducat-unit/core/validate'

import type { PSBTOutput } from '@ducat-unit/core'

import type {
  VaultBorrowRequestConfig,
  VaultBorrowRequestCtx,
  VaultOpenRequestConfig,
  VaultOpenRequestCtx,
  VaultRepayRequestCtx
} from '@/types/index.js'

/**
 * Create the UNIT issuance account output from the account template UTXO.
 * @param vault_ctx - Request context carrying the issue account.
 * @returns PSBT output for the issue account destination.
 */
export function create_issue_account_output (
  vault_ctx : VaultOpenRequestConfig | VaultBorrowRequestConfig
) : PSBTOutput {
  // Get the coin utxo for the unit account.
  const issue_utxo = get_asset_account_utxo(vault_ctx.issue_account)
  // Create the PSBT output.
  return PSBT.create_psbt_output(issue_utxo)
}

/**
 * Create a change output returning extra sats to the issue account script.
 * @param vault_ctx - Request context with issue account and postage.
 * @returns PSBT output for issue-account change.
 */
export function create_issue_change_output (
  vault_ctx : VaultOpenRequestCtx | VaultBorrowRequestCtx
) : PSBTOutput {
  const { issue_account, unit_postage } = vault_ctx
  // Assert that the unit postage is defined.
  Assert.exists(unit_postage, 'unit postage is missing from vault context')
  // Assert the postage is above the dust limit.
  assert_dust_limit(unit_postage, 'postage is below dust limit')
  // Get the script pubkey for the unit address.
  const script_pk = issue_account.coin_script
  // Create the PSBT output.
  return PSBT.create_psbt_output({ value: unit_postage, script_pk })
}

/**
 * Create a change output paying back to the caller's UNIT address.
 * @param vault_ctx - Request context with `unit_address` and `unit_postage`.
 * @returns PSBT output for UNIT-address postage change.
 */
export function create_unit_change_output (
  vault_ctx : VaultOpenRequestCtx | VaultBorrowRequestCtx | VaultRepayRequestCtx
) : PSBTOutput {
  // Unpack the unit address and postage.
  const { unit_address, unit_postage } = vault_ctx
  // Assert that the delivery address and postage are defined.
  Assert.exists(unit_address, 'unit address is missing from vault context')
  Assert.exists(unit_postage, 'unit postage is missing from vault context')
  // Assert the postage is above the dust limit.
  assert_dust_limit(unit_postage, 'postage is below dust limit')
  // Get the script pubkey for the unit address.
  const script_pk = P2TR.decode_address(unit_address).script.hex
  // Create the PSBT output.
  return PSBT.create_psbt_output({ value: unit_postage, script_pk })
}
