/**
 * @fileoverview Utility functions for vault operations.
 *
 * Contains helpers for address parsing and taproot script construction.
 */

import { Buff }            from '@vbyte/buff'
import { parse_address }   from '@vbyte/btc-dev/address'
import { encode_script }   from '@vbyte/btc-dev/script'
import { UNSPENDABLE_KEY } from '@ducat-unit/core/const'

import {
  create_taproot,
  encode_tapscript
} from '@vbyte/btc-dev/taproot'

/**
 * Parses a Bitcoin address and returns its scriptPubKey.
 *
 * @param address - Bitcoin address to parse (any valid format: P2PKH, P2SH, P2WPKH, P2WSH, P2TR)
 * @returns The scriptPubKey as a Uint8Array
 * @throws If the address is empty or invalid
 */
export function get_address_script (address : string) {
  // Validate and parse the address.
  if (typeof address !== 'string' || address.trim() === '') {
    throw new Error('invalid address: address must be a non-empty string')
  }
  try {
    const parsed = parse_address(address)
    return Buff.hex(parsed.script.hex)
  } catch (err) {
    throw new Error(`invalid address: ${address}`, { cause: err })
  }
}

/**
 * Creates a Taproot output script from a list of spending scripts.
 * Uses an unspendable internal key so the output can only be spent
 * via one of the provided scripts.
 *
 * @param scripts - Array of spending scripts to include in the Taproot tree
 * @returns P2TR scriptPubKey as a Uint8Array
 */
export function create_taproot_script_key (
  scripts : Uint8Array[]
) : Uint8Array {
  const leaves  = scripts.map(s => encode_tapscript(s))
  const ctx     = create_taproot({ leaves, pubkey: UNSPENDABLE_KEY })
  return encode_script([ 'OP_1', ctx.tapkey ])
}

