/**
 * @fileoverview Esplora-compatible fetch helpers for transactions, address UTXOs, and broadcast.
 */

import { Assert, Fetch, Resolve } from '@vbyte/util'
import { get_address_script }     from '@/module/vault/index.js'
import { safe_path_segment } from './util.js'
import * as SCHEMA                from '@/schema/index.js'

import type { CoinUtxo }      from '@ducat-unit/core'
import type { EsploraTxData } from '@/types/index.js'

/**
 * Fetch transaction details from an Esplora-compatible endpoint.
 *
 * @param host_url - Base URL of the Explorer API server
 * @param txid     - Transaction hash to lookup
 * @returns Transaction data or error response
 */
export async function fetch_esplora_tx (
  host_url : string,
  txid     : string
) : Promise<Fetch.Type<EsploraTxData>> {
  // Verify txid is a valid hash format
  Assert.is_hash(txid)
  // Define the URL to fetch from.
  const url = `${host_url}/tx/${txid}`
  // Fetch a json response from the server.
  const res = await Fetch.json(url)
  // If the response failed, return early.
  if (!res.ok) return res
  // Define the schema for the response.
  const schema = SCHEMA.esplora.tx_data
  // Try to parse the response data.
  const parsed = schema.safeParse(res.data)
  // If the parsing fails, return the error.
  if (!parsed.success) return Resolve.error(parsed.error, 600)
  // Return the parsed data.
  return Resolve.data(parsed.data)
}

/**
 * Fetch UTXOs for a Bitcoin address from Esplora.
 *
 * @param host_url - Base URL of the Explorer API server
 * @param address  - Bitcoin address to lookup UTXOs for
 * @param filter   - Optional array of satoshi amounts to filter UTXOs by
 * @returns Array of UTXO data or error response
 */
export async function fetch_esplora_utxos (
  host_url : string,
  address  : string
) : Promise<Fetch.Type<CoinUtxo[]>> {
  // Validate the address path segment before interpolation (Codex F26).
  const seg = safe_path_segment(address, 'address')
  // Define the URL to fetch from.
  const url = `${host_url}/address/${seg}/utxo`
  // Fetch a json response from the server.
  const res = await Fetch.json(url)
  // If the response failed, return early.
  if (!res.ok) return res
  // Define the schema for the response.
  const schema = SCHEMA.esplora.address_utxo.array()
  // Try to parse the response data.
  const parsed = schema.safeParse(res.data)
  // If the parsing fails, return the error.
  if (!parsed.success) return Resolve.error(parsed.error, 600)
  // Get the script pubkey for the address.
  const script_pk = get_address_script(address).hex
  // Map the response data to the CoinUtxo type.
  const utxos = parsed.data.map(e => ({ ...e, script_pk }))
  // Return the parsed data.
  return Resolve.data(utxos)
}

/**
 * Broadcast a raw transaction through an Esplora endpoint.
 *
 * @param host_url - Base URL of the Explorer API server
 * @param txhex    - Raw transaction hex to broadcast
 * @returns Transaction ID if successful, error response if failed
 */
export async function post_esplora_tx (
  host_url : string,
  txhex    : string
) : Promise<Fetch.Type<string>> {
  // Verify txhex is valid hex format.
  Assert.is_hex(txhex)
  // Define the URL to post to.
  const url = `${host_url}/tx`
  // Define the options for the POST request.
  const opt = { body: txhex, method: 'POST' }
  // Fetch and return the response as text.
  return Fetch.text(url, opt)
}
