/**
 * @fileoverview Bounded in-memory ring buffer logger for deferred capture.
 *
 * Designed for consumers (frontend bug-report flows, debug overlays) that
 * need to retain a recent window of structured log events without an
 * external sink. Bounds by event count and approximate byte size; never
 * blocks emission.
 */

import { redact_observe_fields } from './redact.js'

import type {
  LogEvent,
  LogLevel,
  SdkLogger
} from './types.js'

const LEVEL_ORDER : Record<LogLevel, number> = {
  error : 0,
  warn  : 1,
  info  : 2,
  debug : 3,
  trace : 4
}

const DEFAULT_MAX_EVENTS = 500
const DEFAULT_MAX_BYTES  = 256 * 1024
const DEFAULT_LEVEL      : LogLevel = 'debug'

export interface RingBufferLoggerOptions {
  level?            : LogLevel
  max_events?       : number
  max_bytes?        : number
  redact_sensitive? : boolean
  unsafe_payloads?  : boolean
}

export interface RingBufferLogger extends SdkLogger {
  snapshot () : LogEvent[]
  clear    () : void
  size     () : { events : number, bytes : number }
}

function approximate_size (event : LogEvent) : number {
  try {
    return JSON.stringify(event).length
  } catch {
    return 0
  }
}

export function create_ring_buffer_logger (
  options : RingBufferLoggerOptions = {}
) : RingBufferLogger {
  const level            = options.level      ?? DEFAULT_LEVEL
  const max_events       = options.max_events ?? DEFAULT_MAX_EVENTS
  const max_bytes        = options.max_bytes  ?? DEFAULT_MAX_BYTES
  const redact_sensitive = options.redact_sensitive ?? true
  const unsafe_payloads  = options.unsafe_payloads  ?? false

  const events : LogEvent[] = []
  const sizes  : number[]   = []
  let total_bytes = 0

  function evict_until_within_bounds () {
    while (events.length > max_events && events.length > 0) {
      events.shift()
      total_bytes -= sizes.shift() ?? 0
    }
    while (total_bytes > max_bytes && events.length > 1) {
      events.shift()
      total_bytes -= sizes.shift() ?? 0
    }
  }

  return {
    enabled (l : LogLevel) {
      return LEVEL_ORDER[l] <= LEVEL_ORDER[level]
    },
    emit (event : LogEvent) {
      if (LEVEL_ORDER[event.level] > LEVEL_ORDER[level]) return

      const safe_event : LogEvent = redact_sensitive
        ? {
            ...event,
            fields : event.fields !== undefined
              ? redact_observe_fields(event.fields, true, unsafe_payloads)
              : undefined
          }
        : event

      const size = approximate_size(safe_event)
      events.push(safe_event)
      sizes.push(size)
      total_bytes += size
      evict_until_within_bounds()
    },
    snapshot () {
      return events.slice()
    },
    clear () {
      events.length = 0
      sizes.length  = 0
      total_bytes   = 0
    },
    size () {
      return { events: events.length, bytes: total_bytes }
    }
  }
}
