/**
 * @fileoverview Validator API fetch helpers for vault profiles (all, latest, history).
 */

import { Fetch, Resolve }          from '@vbyte/util'
import {
  validate_fetch_list_response,
  validate_fetch_response,
  safe_path_segment
} from './util.js'
import * as SHARED                 from '@ducat-unit/core/schema'

import type {
  VaultProfile
} from '@ducat-unit/core'

/**
 * Fetches all vault profiles from the validator API
 * @param host_url - Base URL of the validator API server
 * @param page_size - Maximum number of records to return
 * @param cursor   - Opaque cursor for the next page
 * @returns Array of vault profile data or error response
 */
export async function fetch_vault_all (
  host_url : string,
  page_size? : number,
  cursor?  : string
) : Promise<Resolve.Type<VaultProfile[]>> {
  const url = new URL(`${host_url}/api/vault/all`)
  if (page_size !== undefined) url.searchParams.set('page_size', String(page_size))
  if (cursor !== undefined) url.searchParams.set('cursor', cursor)
  const res = await Fetch.json(url.toString())
  if (!res.ok) return res
  return validate_fetch_list_response(
    SHARED.vault.profile.array(),
    res.data,
    'vault list validation failed'
  )
}

/**
 * Fetches the latest vault profile by root txid from the validator API
 * @param host_url  - Base URL of the validator API server
 * @param root_txid - The vault's root transaction ID
 * @returns Vault profile data or error response
 */
export async function fetch_vault_latest (
  host_url  : string,
  root_txid : string
) : Promise<Resolve.Type<VaultProfile>> {
  const seg = safe_path_segment(root_txid, 'root_txid')
  const url = `${host_url}/api/vault/${seg}/latest`
  const res = await Fetch.json(url)
  if (!res.ok) return res
  return validate_fetch_response(
    SHARED.vault.profile,
    res.data,
    'vault profile validation failed'
  )
}

/**
 * Fetches vault state history by root txid from the validator API
 * @param host_url  - Base URL of the validator API server
 * @param root_txid - The vault's root transaction ID
 * @param options   - Optional history filters
 * @returns Array of vault profile data or error response
 */
export async function fetch_vault_history (
  host_url  : string,
  root_txid : string,
  options?  : {
    action?     : string
    sort_by?    : 'date' | 'btc' | 'unit'
    sort_order? : 'asc' | 'desc'
  }
) : Promise<Resolve.Type<VaultProfile[]>> {
  const seg = safe_path_segment(root_txid, 'root_txid')
  const url = new URL(`${host_url}/api/vault/${seg}/history`)
  if (options?.action !== undefined) url.searchParams.set('action', options.action)
  if (options?.sort_by !== undefined) url.searchParams.set('sort_by', options.sort_by)
  if (options?.sort_order !== undefined) url.searchParams.set('sort_order', options.sort_order)
  const res = await Fetch.json(url.toString())
  if (!res.ok) return res
  return validate_fetch_response(
    SHARED.vault.profile.array(),
    res.data,
    'vault history validation failed'
  )
}
