/**
 * @fileoverview Redaction helpers for observability payloads.
 */

const ALWAYS_REDACT_KEYS = [
  'private',
  'secret',
  'seckey',
  'sighash'
]

const PAYLOAD_KEYS = [
  'psbt',
  'script'
]

function includes_redacted_key (key : string, patterns : string[]) {
  const lower = key.toLowerCase()
  return patterns.some(pattern => lower.includes(pattern))
}

function summarize_payload (label : string, value : unknown) {
  if (typeof value === 'string') {
    return `[REDACTED_${label} len=${value.length}]`
  }
  if (value instanceof Uint8Array) {
    return `[REDACTED_${label} len=${value.length}]`
  }
  return `[REDACTED_${label}]`
}

function redact_value (
  key            : string,
  value          : unknown,
  redact_payload : boolean
) : unknown {
  if (value === null || value === undefined) {
    return value
  }

  if (includes_redacted_key(key, ALWAYS_REDACT_KEYS)) {
    return '[REDACTED]'
  }

  if (redact_payload && includes_redacted_key(key, PAYLOAD_KEYS)) {
    const label = key.toLowerCase().includes('psbt') ? 'PSBT' : 'SCRIPT'
    return summarize_payload(label, value)
  }

  if (Array.isArray(value)) {
    return value.map(entry => redact_value(key, entry, redact_payload))
  }

  if (value instanceof Uint8Array) {
    return redact_payload
      ? summarize_payload('BYTES', value)
      : Array.from(value)
  }

  if (typeof value === 'object') {
    const redacted : Record<string, unknown> = {}
    for (const [ child_key, child_value ] of Object.entries(value as Record<string, unknown>)) {
      redacted[child_key] = redact_value(child_key, child_value, redact_payload)
    }
    return redacted
  }

  return value
}

export function redact_observe_fields (
  fields           : Record<string, unknown>,
  redact_sensitive : boolean,
  unsafe_payloads  : boolean
) : Record<string, unknown> {
  if (!redact_sensitive) return fields

  const redacted : Record<string, unknown> = {}
  for (const [ key, value ] of Object.entries(fields)) {
    redacted[key] = redact_value(key, value, !unsafe_payloads)
  }
  return redacted
}
