/**
 * @fileoverview Vault-commit inscription helper for the SDK.
 */

import { Buff } from '@vbyte/buff'

import { encode_inscriptions } from '@ducat-unit/core/lib'

import type { ProtoProfile, VaultConfigData } from '@ducat-unit/core'

/**
 * Build the vault-commit inscription payload for a new vault: a JSON inscription
 * carrying the vault label, scoped to the protocol's domain hash.
 *
 * @param proto_profile - The active protocol profile (provides the domain hash).
 * @param vault_config  - The vault configuration (provides the label).
 * @returns The hex-encoded inscription payload.
 */
export function create_vault_commit (
  proto_profile : ProtoProfile,
  vault_config  : VaultConfigData
) : string {
  // Create the encoded vault data.
  const content = Buff.json({ lbl : vault_config.label })
  // Create the inscription payload.
  return encode_inscriptions([{
    content  : content.hex,
    mimetype : 'application/json',
    protocol : proto_profile.domain_hash
  }])
}
