/**
 * @fileoverview WebSocket client with type-guarded subscriptions to events.
 */

import { Buff }           from '@vbyte/buff'
import { parse_error }    from '@vbyte/util/helpers'
import { EventEmitter }   from './emitter.js'
import { SUB_TIMEOUT }    from '@/const.js'
import { WebSocketError } from '@/lib/errors/index.js'
import {
  child_observe_context,
  emit_debug,
  emit_error,
  emit_info,
  emit_warn,
  get_observe_context,
} from '@/lib/observe/index.js'

import type {
  MessageConfig,
  MessageData,
  SubscriptionEventMap,
  SubscriptionResult,
  WebSocketEventMap
} from '@/types/index.js'
import type {
  ObserveContext,
  ObservabilityOptions
} from '@/lib/observe/index.js'

import * as SCHEMA from '@/schema/index.js'

/** Maximum length for bounced message data to prevent log pollution */
const MAX_BOUNCED_DATA_LENGTH = 500

export interface WebSocketClientOptions {
  allow_insecure_ws? : boolean
  observability?     : ObservabilityOptions | ObserveContext
}

/**
 * Sanitizes raw message data for safe logging in bounced events.
 * Truncates long messages and redacts binary data.
 *
 * @internal Exported for regression coverage of Codex F31 — malformed WS
 *   frames must never leak the full payload to observability.
 */
export function sanitize_bounced_data (data: unknown): string {
  if (data === null || data === undefined) {
    return '[empty]'
  }
  if (data instanceof ArrayBuffer || data instanceof Uint8Array) {
    return '[binary data]'
  }
  const str = typeof data === 'string' ? data : String(data)
  if (str.length > MAX_BOUNCED_DATA_LENGTH) {
    return `${str.slice(0, MAX_BOUNCED_DATA_LENGTH)}...[truncated]`
  }
  return str
}

function get_socket_error_reason (err: unknown): string {
  const reason = parse_error(err)
  if (typeof reason === 'string' && reason !== '[object ErrorEvent]') {
    return reason
  }
  if (err instanceof Error) {
    return err.message
  }
  if (typeof err === 'object' && err !== null && 'error' in err) {
    return parse_error((err as { error: unknown }).error)
  }
  return 'websocket connection error'
}

/**
 * Validates WebSocket URL and enforces secure connections.
 * TLS is enforced by default unless explicitly opted out via
 * `allow_insecure_ws` for local development/testing.
 * @throws {Error} If using ws:// without explicit opt-in
 */
function validate_socket_url (
  url      : string,
  observe  : ObserveContext,
  options  : WebSocketClientOptions
): void {
  if (!url.startsWith('wss://') && !url.startsWith('ws://')) {
    throw new WebSocketError('Invalid WebSocket URL protocol. Expected ws:// or wss://')
  }

  const is_insecure        = url.startsWith('ws://')
  const allow_insecure     = options.allow_insecure_ws === true

  if (is_insecure && !allow_insecure) {
    throw new WebSocketError(
      'Insecure WebSocket connections (ws://) are not allowed. Use wss:// instead, '
      + 'or set allow_insecure_ws=true for local development/testing.'
    )
  }

  if (is_insecure) {
    emit_warn(
      observe,
      'guardian.socket.warning',
      'insecure websocket connection enabled for local development',
      { socket_url : url }
    )
  }
}

export class WebSocketClient extends EventEmitter<WebSocketEventMap> {

  private readonly _observe : ObserveContext
  private readonly _socket  : WebSocket
  private readonly _url     : string

  constructor (
    socket  : string | WebSocket,
    options : WebSocketClientOptions = {}
  ) {
    // Initialize the event emitter.
    super()

    // Set the URL and socket object.
    this._url    = typeof socket === 'string' ? socket : (socket.url || '')
    this._socket = typeof socket === 'string' ? new WebSocket(this._url) : socket
    this._observe = get_observe_context(options.observability, {
      module     : 'websocket',
      socket_url : this._url
    })
    // URL normalization differs for client-constructed sockets vs server-side
    // wrappers where URL may be missing/path-only.

    // Validate the URL for security.
    // Skip validation for server-side connections which either have no URL
    // or have a path-only URL (e.g., '/api/socket' from the request path).
    const is_server_side = typeof socket !== 'string'
    const is_full_url    = this._url.startsWith('ws://') || this._url.startsWith('wss://')
    if (is_full_url) {
      validate_socket_url(this._url, this.observe, options)
    } else if (!is_server_side && this._url) {
      // Client-side connection with invalid URL protocol
      validate_socket_url(this._url, this.observe, options)
    }

    emit_info(
      this.observe,
      'guardian.socket.connect.start',
      'opening websocket connection',
      { socket_url : this._url }
    )

    // Subscribe to the socket open and close events.
    this._socket.addEventListener('open',  () => {
      emit_info(this.observe, 'guardian.socket.connect.ready', 'websocket connection ready')
      this.emit('ready', undefined)
    })
    this._socket.addEventListener('close', () => {
      emit_info(this.observe, 'guardian.socket.close', 'websocket connection closed')
      this.emit('close', undefined)
    })

    // Subscribe to the socket error event.
    this._socket.addEventListener('error', (err: unknown) => {
      const reason = get_socket_error_reason(err)
      emit_error(this.observe, 'guardian.socket.error', 'websocket connection error', reason)
      this.emit('error', reason)
    })

    // Subscribe to the socket message events.
    this._socket.addEventListener('message', (event : MessageEvent) => {
      // Parse the message and emit the message event.
      parse_message(event.data)
        .then(msg => {
          emit_debug(this.observe, 'guardian.socket.message.received', {
            message_id     : msg.id,
            message_type   : msg.type,
            payload_length : sanitize_bounced_data(event.data).length,
            topic          : msg.topic
          })
          this.emit('message', msg)
        })
        .catch(err => {
          emit_warn(this.observe, 'guardian.socket.message.bounced', 'websocket message could not be parsed', {
            payload_length : sanitize_bounced_data(event.data).length,
            reason         : parse_error(err)
          })
          this.emit('bounced', parse_error(err), sanitize_bounced_data(event.data))
        })
    })
  }

  get ready () {
    return this._socket.readyState === WebSocket.OPEN
  }

  get url () {
    return this._url
  }

  get observe () {
    return this._observe
  }

  close () {
    this._socket.close()
  }

  send (message : MessageData) {
    // Serialize the message payload.
    const msg = serialize_message(message)
    emit_debug(this.observe, 'guardian.socket.message.sent', {
      message_id     : message.id,
      message_type   : message.type,
      payload_length : msg.length,
      topic          : message.topic
    })
    // Send the message.
    this._socket.send(msg)
  }

  subscribe <T = unknown>(request : MessageConfig) {
    // Return a new subscription object for the given request.
    return new SocketSubscription<T>(this, request)
  }
}

export class SocketSubscription <T> extends EventEmitter<SubscriptionEventMap<T>> {

  private readonly _request : MessageData
  private readonly _socket  : WebSocketClient

  constructor (
    socket  : WebSocketClient,
    request : MessageConfig
  ) {
    // Initialize the event emitter.
    super()

    // Set the request configuration.
    this._request = {
      data  : request.data,
      id    : request.id ?? Buff.random(16).hex,
      topic : request.topic,
      type  : 'request',
    }

    // Set the socket client.
    this._socket = socket

    // Subscribe to the socket message events.
    this.socket.on('message', (msg : MessageData) => {
      try {
        // Handle the message if it matches the filter.
        if (this._filter(msg)) this.emit('message', msg)
      } catch (err) {
        emit_warn(
          child_observe_context(this.socket.observe, { request_id : this.id, topic : this.topic }),
          'guardian.socket.subscription.bounced',
          'subscription message bounced during handling',
          { reason : parse_error(err) }
        )
        // Emit the bounced event.
        this.emit('bounced', parse_error(err), msg)
      }
    })
  }

  get id () {
    return this._request.id
  }

  get socket () {
    return this._socket
  }

  get topic () {
    return this._request.topic
  }

  _connect (timeout : number = SUB_TIMEOUT) : Promise<void> {
    // Create a promise to resolve the connection.
    return new Promise((resolve, reject) => {
      // Check if already connected first (after setting up promise).
      if (this.socket.ready) return resolve()
      const cleanup = () => {
        clearTimeout(timer)
        this.socket.off('ready', handle_ready)
        this.socket.off('error', handle_error)
        this.socket.off('close', handle_close)
      }
      const handle_ready = () => {
        cleanup()
        resolve()
      }
      const handle_error = (reason : string) => {
        cleanup()
        reject(new Error(reason))
      }
      const handle_close = () => {
        cleanup()
        reject(new Error('connection closed'))
      }
      // Set a timeout to reject the promise if the request times out.
      const timer = setTimeout(() => {
        cleanup()
        reject(new Error('connection timed out'))
      }, timeout)
      // Subscribe to the socket lifecycle events.
      this.socket.on('ready', handle_ready)
      this.socket.on('error', handle_error)
      this.socket.on('close', handle_close)
    })
  }

  _filter (msg : MessageData) {
    // Return true if the message matches the filter.
    return (
      msg.type  !== 'request'  && 
      msg.topic === this.topic && 
      msg.id    === this.id
    )
  }

  _resolve (timeout : number) : Promise<SubscriptionResult<T>> {
    // Create a promise to resolve the response.
    return new Promise((resolve) => {
      // Set a timeout to reject the promise if the request times out.
      const timer = setTimeout(() => resolve({ ok: false, reason: 'request timed out' }), timeout)
      // Subscribe to the socket message events.
      this.socket.within('message', (msg : MessageData) => {
        // Check if the message is a response to this request.
        if (msg.id === this.id) {
          // Resolve based on message type.
          if (msg.type === 'result') {
            clearTimeout(timer)
            resolve({ ok: true, data: msg.data as T })
          } else if (msg.type === 'reject') {
            clearTimeout(timer)
            resolve({ ok: false, reason: msg.data as string })
          }
          // `info` and `status` messages are intentionally non-terminal and
          // therefore do not resolve the request promise.
        }
      }, timeout)
    })
  }

  async send (timeout : number = SUB_TIMEOUT) : Promise<SubscriptionResult<T>> {
    try {
      // Wait for the socket to be ready.
      await this._connect(timeout)
    } catch (err) {
      const reason = get_socket_error_reason(err)
      return {
        ok     : false,
        reason : reason.includes('connect') ? reason : `connect failed: ${reason}`
      }
    }
    // Create a promise to resolve the response.
    const promise = this._resolve(timeout)
    // Send the request.
    this.socket.send(this._request)
    // Return the promise for the response.
    return promise
  }
}

/**
 *  Serialize a message to a JSON string.
 */
function serialize_message (msg : MessageData) : string {
  // Extract the id, topic, and data from the message.
  const { id, topic, type, data } = msg
  // Attempt to serialize the message.
  try {
    // Serialize the message to a JSON string.
    return JSON.stringify([ type, id, topic, data ])
  } catch {
    // Throw if the message is invalid.
    throw new WebSocketError(`failed to serialize envelope:\n${msg.toString()}`)
  }
}

/**
 *  Parse a message from a JSON string.
 */
async function parse_message (payload : unknown) : Promise<MessageData> {
  // Convert payload to string if needed.
  let str_payload: string
  if (typeof payload === 'string') {
    str_payload = payload
  } else if (typeof payload === 'object' && payload !== null) {
    if ('text' in payload && typeof (payload as { text: unknown }).text === 'function') {
      str_payload = await (payload as { text: () => Promise<string> }).text()
    } else if (payload instanceof Uint8Array || payload instanceof ArrayBuffer) {
      // Binary-frame path (ws/bun): construct from the asserted byte payload
      // rather than casting an arbitrary object to Uint8Array.
      str_payload = new Buff(payload).str
    } else {
      throw new WebSocketError('invalid payload shape: expected a string, a {text()} blob, or a binary frame')
    }
  } else {
    throw new WebSocketError(`invalid payload type: ${typeof payload}`)
  }
  // Attempt to parse the JSON payload.
  try {
    // Parse the JSON string.
    const json_payload = JSON.parse(str_payload) as unknown
    // Parse the payload.
    const parsed = await SCHEMA.ws.envelope.parseAsync(json_payload)
    // Extract the id, topic, data, and optional code from the payload.
    // The 5th element (reject/status code) was previously dropped,
    // hiding reject reasons from the application (Codex F39).
    const [ type, id, topic, data, code ] = parsed
    // Return the validated payload, including the code when present.
    return (code !== undefined) ? { id, type, topic, data, code } : { id, type, topic, data }
  } catch (err) {
    // Throw if the JSON is invalid. Bound the embedded payload via
    // sanitize_bounced_data (Codex F31): the raw str_payload is
    // unbounded and this message surfaces as the `reason` field on
    // bounced events, which would otherwise bypass
    // MAX_BOUNCED_DATA_LENGTH and leak the full frame to logs.
    throw new WebSocketError(`failed to parse envelope: ${sanitize_bounced_data(str_payload)}`, { cause: err })
  }
}
