/**
 * @fileoverview UNIT-specific vault helpers for address and balance arithmetic.
 */

import { get_address }    from '@vbyte/btc-dev/address'
import { get_asset_pool, to_address_network } from '@ducat-unit/core/lib'

import type {
  VaultBorrowRequestCtx,
  VaultRequestCtx,
  VaultOpenRequestCtx
} from '@/types/index.js'

import type { AssetPool } from '@ducat-unit/core'

/** Derive issuer address from issue account script on protocol network. */
export function get_unit_issuer_address (
  vault_ctx : VaultOpenRequestCtx | VaultBorrowRequestCtx
) : string {
  const account = vault_ctx.issue_account
  const network = vault_ctx.proto_profile.chain_network
  return get_address(account.coin_script, to_address_network(network))
}

/** Build UNIT asset pool view from vault context asset inputs. */
export function get_unit_asset_pool (
  vault_ctx : VaultRequestCtx
) : AssetPool {
  // Unpack the vault context object.
  const { asset_inputs, vault_terms } = vault_ctx
  // Get the unit asset ID.
  const unit_asset_id = vault_terms.unit_asset_id
  // Return the asset pool.
  return get_asset_pool(unit_asset_id, asset_inputs)
}

/**
 * Compute post-repay UNIT balance and reject negative results.
 * @param unit_balance - Current UNIT balance.
 * @param repay_amount - UNIT amount to repay.
 * @returns New UNIT balance after repayment.
 */
export function get_new_unit_balance (
  unit_balance : number,
  repay_amount : number
) : number {
  const new_balance = unit_balance - repay_amount
  if (new_balance < 0) {
    throw new Error(`repay amount is greater than unit balance: ${unit_balance} < ${repay_amount}`)
  }
  return new_balance
}

/**
 * Compute UNIT change amount after repayment input selection.
 * @param input_amount - Total UNIT from selected repay inputs.
 * @param repay_amount - UNIT amount being repaid.
 * @returns Remaining UNIT change amount.
 */
export function get_unit_change (
  input_amount : number,
  repay_amount : number
) : number {
  const change_amt = input_amount - repay_amount
  if (change_amt < 0) {
    throw new Error(`insufficient unit balance from inputs: ${input_amount} < ${repay_amount}`)
  }
  return change_amt
}
