/**
 * @fileoverview Price-contract helpers for the SDK.
 */

import type { PriceContract } from '@ducat-unit/core'

/**
 * Filters a list of price contracts to only include those matching the given commit hashes.
 *
 * @param price_contracts - The array of price contracts to filter.
 * @param commit_hashes   - The array of price commit hashes to match against.
 * @returns An array of price contracts whose commit hash matches the given commit hashes.
 */
export function filter_price_contracts (
  price_contracts : PriceContract[],
  commit_hashes   : string[]
) : PriceContract[] {
  // Return the filtered price contracts using the price commit hashes.
  return price_contracts.filter(c => commit_hashes.includes(c.commit_hash))
}
