/**
 * @fileoverview Transaction byte-size constants for inputs, outputs, witnesses, and scripts.
 */

/** Base size of a transaction:
 * - locktime     (4 bytes)
 * - version      (4 bytes)
 * - vin count    (1 byte)
 * - vout count   (1 byte)
 * - witness flag (2 bytes)
 */
export const TX_BASE_SIZE = 12

/** Base size of a transaction output (P2WPKH and P2TR): */
export const VOUT_P2WPKH_SIZE = 31 // value(8) + varint(1) + opcode(1) + script size(1) + script_pk(20)
export const VOUT_P2TR_SIZE   = 43 // value(8) + varint(1) + opcode(1) + script size(1) + script_pk(32)

/**
 * Sizes for various OP_RETURN outputs:
 */
export const OP_RETURN_BASE_SIZE     = 9  // value(8) + varint(1)
export const VAULT_RETURN_BASE_SIZE  = 12 // value(8) + varint(1) + magic(1) + script size(1) + version(1)
export const VAULT_RETURN_GUARD_DATA = 1  // guard count(1)
export const VAULT_RETURN_PRICE_DATA = 8  // unit balance(4) + price stamp(4)

/**
 * Witness stack element sizes (no discount):
 */
export const STACK_COUNT      = 1  // For stack count.
export const HASH_PREIMG_SIZE = 32 // For hash preimage.
export const P2WPKH_KEY_SIZE  = 33 // compressed ECDSA public key.
export const P2WPKH_SIG_SIZE  = 73 // For compressed ECDSA signatures.
export const P2TR_SIG_SIZE    = 64 // For schnorr signatures (without a sighash flag).
export const CBLOCK_KEY_SIZE  = 33 // For control block internal key.
export const CBLOCK_HASH_SIZE = 32 // For control block merkle path hash.

/** Script sizes for various spending types: */
export const COSIGN_SPEND_SCRIPT_SIZE = 69 // varint(1) + OP_DATA (1) + client_pk (32) + OP_CHECKSIGVERIFY (1) + OP_DATA (1) + guard_pk (32) + OP_CHECKSIG (1)
export const LIQUID_SPEND_SCRIPT_SIZE = 58 // varint(1) + OP_HASH160 (1) + OP_DATA (1) + thold_hash (20) + OP_EQUALVERIFY (1) + OP_DATA (1) + guard_pk (32) + OP_CHECKSIG (1)

/** Witness sizes (discounted) for P2WPKH and P2TR spending inputs: */
export const WIT_P2WPKH_SPEND_SIZE = 27
export const WIT_P2TR_SPEND_SIZE   = 17

/**
 * Sizes for various spending inputs:
 * - txid       (32 bytes)
 * - vout       (4 bytes)
 * - sequence   (4 bytes)
 * - script_sig (1 byte)
 */
export const VIN_BASE_SIZE = 41

/* Sizes for transaction spending inputs: */
export const VIN_P2WPKH_SPEND_SIZE = VIN_BASE_SIZE + WIT_P2WPKH_SPEND_SIZE
export const VIN_P2TR_SPEND_SIZE   = VIN_BASE_SIZE + WIT_P2TR_SPEND_SIZE

export const ASSET_ISSUE_TX_BASE_SIZE =
  VIN_P2TR_SPEND_SIZE + // guardian asset input
  VOUT_P2TR_SIZE      + // guardian asset output
  VOUT_P2TR_SIZE      + // borrower asset output
  VOUT_P2TR_SIZE      + // vault connector output
  OP_RETURN_BASE_SIZE   // runestone output

export const ASSET_BURN_TX_BASE_SIZE =
  VOUT_P2TR_SIZE      + // vault connector output (always present; Codex F28)
  OP_RETURN_BASE_SIZE   // runestone output

export const VAULT_OPEN_TX_BASE_SIZE =
  VIN_P2TR_SPEND_SIZE + // borrower asset input
  VIN_BASE_SIZE       + // vault connector input
  VOUT_P2TR_SIZE      + // borrower asset output
  VOUT_P2TR_SIZE      + // vault collateral output
  VOUT_P2TR_SIZE      + // change output
  OP_RETURN_BASE_SIZE   // vault return data output

export const VAULT_BORROW_TX_BASE_SIZE =
  VIN_P2TR_SPEND_SIZE + // borrower asset input
  VIN_BASE_SIZE       + // vault collateral input
  VIN_BASE_SIZE       + // vault connector input
  VOUT_P2TR_SIZE      + // borrower asset output
  VOUT_P2TR_SIZE      + // vault collateral output
  VOUT_P2TR_SIZE      + // change output
  OP_RETURN_BASE_SIZE // vault return data output

export const VAULT_REPAY_TX_BASE_SIZE =
  VIN_BASE_SIZE     + // vault collateral input
  VIN_BASE_SIZE     + // vault connector input
  VOUT_P2TR_SIZE    + // vault collateral output
  VOUT_P2TR_SIZE    + // change output
  OP_RETURN_BASE_SIZE // vault return data output

export const VAULT_UPDATE_TX_BASE_SIZE =
  VIN_BASE_SIZE     + // vault collateral input
  VOUT_P2TR_SIZE    + // vault collateral output
  VOUT_P2TR_SIZE    + // change output
  OP_RETURN_BASE_SIZE // vault return data output

export const VAULT_CLOSE_TX_BASE_SIZE =
  VIN_BASE_SIZE     + // vault collateral input
  VOUT_P2TR_SIZE    + // change output
  OP_RETURN_BASE_SIZE // vault return data output
