/**
 * @fileoverview Shared fetch helpers: URL path-segment sanitization and
 * fetch-response validation and freshness checks.
 */

import { Resolve }       from '@vbyte/util'
import { safe_validate } from '@/lib/validate/index.js'

import type { ZodSchema } from 'zod'

/** Default maximum response age: 10 minutes */
const DEFAULT_MAX_RESPONSE_AGE_MS = 10 * 60 * 1000

/**
 * Character allowlist for values interpolated into a URL path segment
 * (Codex F26). The allowlist IS the security control: it permits only
 * the characters that legitimately appear in protocol identifiers —
 * hex, digits, the `:` outpoint/asset delimiter, and `_`/`-` — and
 * thereby excludes every path-significant character (`/ . ? # % @ \`
 * and whitespace) that could inject a traversal sequence or delimiter
 * to redirect a request to an unintended same-host endpoint.
 *
 * It deliberately does NOT enforce a specific identifier *format*
 * (length, hex-ness). That is the server's and the response schema's
 * job; over-strict format checks here only risk rejecting legitimate
 * ids — compressed (66-hex) vs x-only (64-hex) pubkeys, 40- vs 64-char
 * commit roots, hex vs `height:index` asset ids. We also do not
 * encodeURIComponent: compound ids carry a literal `:` the API
 * expects, and percent-encoding it would corrupt the lookup, while the
 * allowlist already guarantees URL-path safety.
 */
const PATH_SAFE_SEGMENT = /^[A-Za-z0-9:_-]+$/

/**
 * Validate a value destined for a URL path segment against the
 * path-safe character allowlist and return it unchanged (Codex F26).
 *
 * @param value - The caller-supplied identifier.
 * @param label - Human-readable label for the error message.
 * @throws Error if the value is empty or contains a path-unsafe char.
 */
export function safe_path_segment (
  value : string,
  label : string = 'path segment'
) : string {
  if (typeof value !== 'string' || value.length === 0 || !PATH_SAFE_SEGMENT.test(value)) {
    throw new Error(`invalid ${label} for URL path: ${String(value)}`)
  }
  return value
}

export interface FetchValidationOptions {
  /**
   * Maximum allowed age of the response in milliseconds.
   * Validates the response timestamp (if present) is within this window.
   * Set to 0 to disable freshness checking.
   * @default 600000 (10 minutes)
   */
  max_age_ms? : number
}

function unwrap_paginated_items (data : unknown) : unknown {
  if (typeof data !== 'object' || data === null) return data
  const record = data as Record<string, unknown>
  if ('data' in record) return record.data
  return 'items' in record ? record.items : data
}

/**
 * Validates that a response timestamp is fresh (not stale).
 * If the response contains a timestamp field, verifies it is within the allowed window.
 *
 * @param data - Response data that may contain a timestamp field
 * @param max_age_ms - Maximum allowed age in milliseconds
 * @returns Error string if stale, undefined if fresh or no timestamp
 */
export function validate_response_freshness (
  data       : unknown,
  max_age_ms : number = DEFAULT_MAX_RESPONSE_AGE_MS
) : string | undefined {
  // If freshness checking is disabled, skip.
  if (max_age_ms === 0) return undefined
  // Check if data has a timestamp-like field.
  if (typeof data !== 'object' || data === null) return undefined
  const record = data as Record<string, unknown>
  // Check common timestamp field names.
  const timestamp = record.updated_at ?? record.created_at ?? record.timestamp
  if (typeof timestamp !== 'number') return undefined
  // Determine if timestamp is in seconds or milliseconds.
  // Timestamps below 1e12 are in seconds (epoch seconds < year 33658).
  const ts_ms = timestamp < 1e12 ? timestamp * 1000 : timestamp
  const now   = Date.now()
  const age   = now - ts_ms
  if (age > max_age_ms) {
    return `response is stale: age ${Math.round(age / 1000)}s exceeds max ${Math.round(max_age_ms / 1000)}s`
  }
  if (age < -max_age_ms) {
    return `response timestamp is too far in the future: ${Math.round(-age / 1000)}s ahead`
  }
  return undefined
}

/**
 * Validates fetch response data against a schema and returns a Resolve result.
 * Consolidates the common pattern used across all fetch validators.
 *
 * @param schema       - Zod schema to validate response data against
 * @param data         - Raw response data to validate
 * @param error_prefix - Descriptive prefix for validation error messages
 * @param options      - Optional freshness validation settings
 * @returns Resolve.Type with either validated data or error
 */
export function validate_fetch_response<T> (
  schema       : ZodSchema<T>,
  data         : unknown,
  error_prefix : string,
  options?     : FetchValidationOptions
): Resolve.Type<T> {
  // Validate response freshness only when explicitly enabled.
  if (options?.max_age_ms !== undefined && options.max_age_ms > 0) {
    const freshness_error = validate_response_freshness(data, options.max_age_ms)
    if (freshness_error) {
      return Resolve.error(`${error_prefix}: ${freshness_error}`)
    }
  }
  const result = safe_validate(schema, data, { error_prefix })
  if (!result.ok) return Resolve.error(result.error)
  return Resolve.data(result.data)
}

/**
 * Validates list-style fetch responses, accepting either a raw array response
 * or a cursor-pagination envelope with a `data` array.
 */
export function validate_fetch_list_response<T> (
  schema       : ZodSchema<T>,
  data         : unknown,
  error_prefix : string,
  options?     : FetchValidationOptions
) : Resolve.Type<T> {
  return validate_fetch_response(
    schema,
    unwrap_paginated_items(data),
    error_prefix,
    options
  )
}
